window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q15"]=window.__LIBQ["tien-nghich"]["q15"]||{};window.__LIBQ["tien-nghich"]["q15"]["characters"]={"updatedAt":"2026-07-14","count":51,"chars":[{"id":"vuong-lam","name":"Vương Lâm","canhGioiCaoNhat":"Đại Hồn sư (Đại thành)","trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1579","importance":"normal","mucCt":"ky","tieuDe":"Dung hợp đầu lâu Đạo Cổ, đại chiến con trai Diệp Mịch","text":"Dung hợp thân thể với đầu lâu Đạo Cổ Diệp Mịch, hóa thành mắt trái bị mất khiến đầu lâu đầy đủ. Va chạm lần đầu bị thương nặng, mi tâm lưu vết thương, hai mắt chảy huyết lệ, thị lực mơ hồ nhuộm đỏ. Dùng Thanh Quang Thuẫn kích hoạt Mộng Hồi Viễn Cổ đã hòa Mộng đạo, kéo tinh không về viễn cổ nhưng bị thuật Tê Thiên xuyên phá. Thi triển Nhân Quả Ấn kéo khí tức đối thủ, rồi vỗ Sinh Tử Ấn nhưng không ngăn nổi cơn điên cuồng. Thân thể bị Tê Thiên xé rách từ mi tâm tới bụng, da thịt lộ xương cốt, xương bắt đầu vỡ vụn. Dù bị thương trầm trọng vẫn khát vọng giết đối thủ đoạt thuật Tê Thiên.","anchor":"da thịt đang bị xé ra lộ cả xương cốt"},{"importance":"normal","mucCt":"ky","chuong":"@c1580","tieuDe":"Dung hợp Mộng đạo — giết con trai Diệp Mịch","text":"Trong tình thế xương đầu nứt, lồng ngực rách, dung hợp Mộng đạo thuật với Mộng hồi viễn cổ của Thanh Quang Thuẫn, trở thành chúa tể giấc mộng, biến toàn bộ thiên địa thành đôi mắt khổng lồ nghiền nát con trai Diệp Mịch trong mộng. Mộng tỉnh, dùng huyết kiếm chém đôi đối phương đang mê mang, thu tám giọt máu tím vào mi tâm nhưng chưa dung hợp. Bị thương cực nặng do tổn thương trong mộng phản ánh lên thân thật, phun máu, vào Vô Danh Chuyển Luân trận khoanh chân chữa thương. Nén thương truyền tu vị vào đại trận, kích hoạt bánh xe khổng lồ nghiền nát mấy vạn tu sĩ giới ngoại, hấp thu nguyên thần. Rút cung Lý Quảng kéo căng dây cung uy hiếp Chưởng Tôn buộc rút lui. Chữa thương suốt chín tháng, hết một năm thì Tây Tử Phượng rời đi, bên cạnh chỉ còn nữ tử áo hồng.","anchor":"Mộng đạo thuật dung hợp với Mộng hồi viễn cổ. Mộng này là mộng của ta."},{"importance":"normal","mucCt":"ky","chuong":"@c1582","tieuDe":"Chấn động bổn nguyên — Lam Mộng quy thuận","text":"Hồng Điệp tiết lộ sư tôn từng gặp đại nho họ Vương, người đặt tên cho nàng, khiến Vương Lâm chấn động mãnh liệt vì giấc mộng bổn nguyên tưởng tự tạo ra bằng thuật lừa gạt bản thân lại có dấu vết thật. Hắn rơi vào hoài nghi ranh giới thật–giả của bổn nguyên viên mãn. Kể cho Hồng Điệp về thân thế Thanh Thủy: toàn tộc bị diệt, thê tử chết, chỉ còn nữ nhi đã luân hồi với thai ký màu hồng trên vai trái không bao giờ tiêu tán. Nhập định tới tháng thứ sáu năm thứ ba mới tỉnh, trả lời Lam Mộng Đạo Tôn rằng mình đã có thê tử, gián tiếp từ chối hôn sự với Lý Thiến Mai. Lam Mộng tuyên bố không đánh hắn nữa, sẵn lòng liên thủ. Ba kẻ địch Diệu Âm, Cửu Thiên, Đại Hoang được Chưởng Tôn cứu khỏi cổ mộ lao tới tấn công, nhưng Lam Mộng chủ động chặn hộ.","anchor":"Tất cả mọi chuyện rõ ràng là giấc mộng do mình tạo ra, dùng thuật lừa gạt bản thân để tạo thành"},{"chuong":"@c1583","importance":"normal","tieuDe":"Hủy tranh tiếp nhận Lý Thiến Mai","text":"Vương Lâm ngồi trong Vô Danh Chuyển Luân trận dưỡng thương hai năm, hồi phục hơn phân nửa, tiếp tục dung hợp tám giọt máu cổ đạo và nghiên cứu thuật Tê Thiên. Chứng kiến Lam Mộng Đạo Tôn một mình đánh bại ba đại năng trong ba ngày. Tuyên bố cả đời chỉ có một thê tử, ban đầu từ chối đề nghị của Lam Mộng Đạo Tôn. Lý Thiến Mai xin lại bức tranh Tương Vong Vu Giang Hồ để đoạn tuyệt, nói rõ ân không phải tình. Vương Lâm nắm chặt bức tranh không buông, cuối cùng hủy bức tranh, tuyên bố từ nay Lý Thiến Mai là nữ nhân của hắn, đồng thời khẳng định Lý Mộ Uyển vẫn là thê tử, đợi nàng tỉnh dậy sẽ cùng thành thân.","anchor":"Từ nay về sau nàng là nữ nhân của Vương Lâm ta!"},{"importance":"major","mucCt":"ky","chuong":"@c1584","tieuDe":"Phân thân vào giới nội ngưng tụ tứ đại tiên giới","text":"Sau khi Lý Thiến Mai và Mộc Băng Mi lần lượt rời đi, Vương Lâm điểm vào mi tâm tách phân thân tu sĩ (Không Linh trung kỳ, không lực lượng thân thể cường hãn) ra khỏi bổn tôn (Cổ Thần/Cổ Yêu/Cổ Ma, truyền thừa đạo cổ). Bổn tôn ở lại giữ Vô Danh Chuyển Luân trận trong tháng cuối trước khi tứ đại chiến tướng ra khỏi viễn cổ tiên vực. Phân thân bước vào tinh không giới nội thực hiện kế hoạch ngưng tụ tứ đại tiên giới dung hợp thành một tân tiên giới, để tu sĩ giới nội có thể ngưng tụ hương hỏa lực và tu sĩ mới sinh có thể tu tiên rồi phi thăng. Phân thân đầu tiên tới Phong Tiên giới ở Vân Hải tinh vực, cảm ứng được Văn thú thất lạc trăm năm đang ở đó. Con Văn thú khổng lồ màu vàng thân trăm vạn trượng khi cảm nhận khí tức chủ nhân liền điên cuồng lao tới, Vương Lâm quay đầu lộ nụ cười vui vẻ. Đối với Mộc Băng Mi, hắn không còn hận nhưng cũng không có tình.","anchor":"bất ngờ từ trong cơ thể hắn huyễn hóa ra một Vương Lâm khác"},{"importance":"normal","mucCt":"ky","chuong":"@c1585","tieuDe":"Khám phá bí mật Phong Tiên giới","text":"Phân thân trong Phong Tiên giới hội ngộ Văn vương trăm trượng dẫn đàn trên vạn Văn thú, nhận ra Văn vương đã tiến hóa gần bước thứ ba chỉ còn kém một bước lột xác. Được Văn vương dẫn vào vùng sâu sương mù, phát hiện pho tượng hình người từng thấy năm xưa đã biến mất. Tìm thấy thi thể Văn thú ngàn trượng bước thứ ba bị giết bằng ba ngón tay xuyên thấu vào cổ, khí tức trên tam chỉ khiến hắn cảm thấy mơ hồ quen thuộc. Dùng ngọc giản bẻ gãy rồi gắn lại để thí nghiệm so sánh, kết luận cái khe khổng lồ đã bị xé mở một lần rồi sửa lại, sau đó bị xé mở lần thứ hai. Theo Văn vương vào bên trong khe, phát hiện không gian tràn ngập huỳnh quang chứa hàng trăm vạn trứng Văn thú các kích cỡ. Tản thần thức bao phủ toàn bộ không gian, phát hiện điều gì đó chấn động khiến hắn kinh ngạc lùi lại mấy bước ngẩng phắt đầu.","anchor":"hai mắt hắn lộ vẻ rung động, thân thể theo tiềm thức lui lại phía sau vài bước, ngẩng phắt đầu"},{"chuong":"@c1586","importance":"major","mucCt":"ky","tieuDe":"Kiếm xuyên phong ấn, phát hiện Tiên Cương","text":"Khám phá thông đạo bí ẩn trong động phủ, cuối thông đạo là cửa đá khổng lồ có lá phù phong ấn hai chiều. Lần đầu xuất nguyên thần dung hợp huyết kiếm tiếp cận nhưng bị lực bài xích đẩy lui. Lần hai bạo phát toàn bộ tu vi, triệu lục đại bổn nguyên — lôi, hỏa, sinh, tử, nhân quả, tam đại hư bổn nguyên, sát lục — ngưng tụ trong huyết kiếm, nguyên thần hóa kiếm xuyên qua phong ấn đâm sâu ba thước vào cửa đá. Cảm nhận được khí tức Tiên Cương đại lục bên kia — mũi kiếm lộ ra ba tấc trên Đông Đan chung của Quy Nhất tông, tỏa huyết quang kinh thiên. Sau đó bị đẩy lui, rút về an toàn, xác nhận bên ngoài cửa đá chính là Tiên Cương đại lục.","anchor":"Tiên Cương đại lục! Bên ngoài cánh cửa đá này không ngờ lại là Tiên Cương đại lục!"},{"importance":"normal","mucCt":"ky","chuong":"@c1587","tieuDe":"Ngưng tụ Phong Tiên giới, tiến về Thiểm Giới","text":"Nhận ra cánh cửa đá trong thông đạo không phải đại môn động phủ Thất Thải Tiên Tôn mà là thông đạo do tu sĩ từ Tiên Cương đại lục mở ra từ bên ngoài để xâm nhập. Liên kết manh mối từ Thiểm Lôi tộc, Côn Cực Tiên, thủ lĩnh giống Nạp Đa, suy ra nhóm tu sĩ thần bí chính là người từ tông phái khác trên Tiên Cương đại lục, có thể vẫn đang ở Ngũ Hành tinh. Thu toàn bộ hàng trăm vạn trứng Văn thú vào không gian trữ vật, phong ấn khe nứt thông đạo bằng cấm chế và cổ Tức Diệp. Dùng tu vi Không Linh trung kỳ bao trùm toàn bộ Phong Tiên giới, ép các mảnh đại lục vỡ vụn ngưng tụ thành một đại lục hoàn chỉnh, gió lốc sụp đổ. Dùng nguyên thần dung hợp mặt đất, điều khiển cả đại lục Phong Tiên giới bay ra tinh không Vân Hải tinh vực, hướng về Triệu Hà để tới Thiểm Giới — tiên giới duy nhất chưa từng đi qua.","anchor":"Phong Tiên giới này giống như một tấm gương đã bị nghiền nát đang từ từ hợp lại"},{"importance":"normal","mucCt":"ky","chuong":"@c1588","tieuDe":"Ngưng tụ Tân tiên giới và tuyên bố nghịch tiên","text":"Điều khiển Phong Tiên giới rời Vân Hải tinh vực tới Triệu Hà, vào Thiểm Giới khảo sát ba ngày rồi nhận định đã bị hủy diệt không thể cứu vãn, vung tay thu cả dải ngân hà Thiểm Giới vờn quanh đại lục Phong Tiên giới làm tầng bảo vệ. Đưa Phong Tiên giới tới La Thiên Tinh Vực khảo sát Lôi Tiên Giới, nhận định đã phế hoàn toàn không thể dùng. Khi rời đi, hạt châu Thiên Nghịch tự lóe sáng phát ra lực lượng kỳ dị giúp nhận biết Chiến lão quỷ đang ẩn thế nhìn mình, nhưng dấu diếm rời đi không vọng động. Tới Côn Hư Vũ giới, hoàn tất khảo sát tứ đại tiên giới. Tại giao điểm tứ đại tiên giới, ngưng tụ Tân tiên giới: lấy đại lục Phong Tiên giới làm căn cơ, dùng bụi bặm Vũ Giới bành trướng đại lục, triển khai Dịch Linh Ấn ngưng tụ, biến ngân hà Thiểm Giới thành tầng bảo vệ phân chia tiên phàm (dưới Hóa Thần không vào được), kích hoạt Vô Danh Chuyển Luân trận hấp thu khí tức Thái cổ Tinh Thần. Phân nguyên thần chỉ đạo mấy vạn tu sĩ do Thanh Lâm dẫn đầu tản ra tứ đại tinh vực rút tinh hồn từ các tu chân tinh, dung hợp vào tân tiên giới, thiết lập cơ chế phi thăng cho tu sĩ đột phá Hóa Thần. Tuyên bố từ bỏ danh xưng Phong Tôn, sắp đi nghịch tiên — thành thì tiên phá, bại thì tử vong. Gửi gắm Tư Đồ Nam nếu mình chết thì bố cáo thiên hạ, viết thành ngọc giản lưu khắp nơi. Bóng lưng cô độc bước đi, mấy vạn tu sĩ vái tiễn.","anchor":"Vương mỗ lần này ra đi sinh tử không rõ, danh xưng Phong Tôn này từ nay về sau ta không giữ nữa"},{"importance":"normal","mucCt":"ky","chuong":"@c1589","tieuDe":"Dung hợp phân thân, tiến vào Thái Cổ Tinh Thần","text":"Vào ba ngày cuối cùng của năm thứ ba, bổn tôn mở mắt bên ngoài Vô Danh Chuyển Luân trận, phân thân bạch y từ giới nội trở về dung hợp vào bổn tôn, phát ra tiếng ầm và ánh sáng nhu hòa. Vương Lâm cảm ngộ sâu sắc rằng cường giả chân chính là người hiểu được sự gánh vác, liên hệ hình ảnh phụ thân phàm nhân che chở gió mưa với con đường tu đạo hơn hai ngàn năm của mình. Quyết định hủy diệt viễn cổ tiên vực giới ngoại và tạo hỗn loạn trước đại chiến, hắn không ẩn giấu khí tức trực tiếp tiến vào Thái Cổ Tinh Thần, thần thức khuếch tán khiến mọi cường giả bừng tỉnh. Dừng lại gần trung tâm Thái Cổ Tinh Thần khoanh chân thổ nạp, vận chuyển giọt máu tiên nhân bất diệt thể trên mi tâm đưa khí tức lên đỉnh phong. Khi còn ba-bốn canh giờ, phát hiện mấy trăm tới hơn ngàn tu sĩ mặt vẽ xanh đỏ gào thét khẩu hiệu Tiên Long Hiển Đạo lao tới.","anchor":"chỉ có cường giả hiểu được chuyện cần gánh vác mới là cường giả chân chính"},{"importance":"normal","mucCt":"ky","chuong":"@c1590","tieuDe":"Chặn đường viêm long","text":"Phát hiện viêm long quen thuộc từ trăm năm trước trong thế giới động phủ, chủ động hiện thân chặn đường nó. Viêm long ngốc nghếch phun hỏa cầu tấn công nhưng Vương Lâm phá tan dễ dàng, thu toàn bộ ngọn lửa vào tay trái, thể hiện thực lực áp đảo hoàn toàn.","anchor":"Vương Lâm từ bên trong ngọn lửa đi ra, bước từng bước một"},{"importance":"normal","mucCt":"ky","chuong":"@c1591","tieuDe":"Thu phục Tiểu Hồng, lộ bí mật Liên Đạo Phi","text":"Dùng ấn quyết Chu Tước đời thứ hai kích hoạt ấn ký trên mi tâm viêm long, khiến nó đau đớn khuất phục. Phát hiện trong thân viêm long ẩn chứa huyết mạch tiên nhân nhờ giọt máu tiên nhân bất diệt thể trên mi tâm. Phối hợp viêm long diễn kịch trước hơn ngàn môn đồ Tiên Long Tông, nhận danh nghĩa phó tông chủ. Viêm long khai nhận tên Tiểu Hồng, xác nhận chủ nhân cũ chính là Liên Đạo Phi — người điên năm xưa — tâm thần chấn động mạnh khi nhớ lại lời người điên nhiều lần gọi Tiểu Hồng. Thu viêm long vào khe trữ vật, bình ổn tâm cảnh trong ba canh giờ cuối trước khi thời hạn ba năm trong Thái Cổ Tinh Thần kết thúc.","anchor":"Tiểu Hồng! Đôi mắt Vương Lâm bừng sáng. Hắn nhìn chằm chằm vào viêm long, trong đầu ầm vang."},{"chuong":"@c1592","importance":"major","tieuDe":"Viễn cổ tiên vực mở ra đúng ước định","text":"Đúng một trăm năm kể từ khi giới nội và giới ngoại khai chiến, cũng là thời hạn ba năm Vương Lâm chờ đợi. Tứ đại chiến tướng viễn cổ tiên vực giới nội đã ước định với hắn triển khai chiến đấu vào ngày này. Thần thức ngưng tụ bên người không ai phát hiện, kịch biến sắp phát sinh. Tứ đại tinh vực tinh không vỡ vụn, khe nứt khổng lồ ngưng tụ thành hình chữ thập tại tân tiên giới. Hơn mười sáu tiên nhân viễn cổ tỏa kim quang bước ra, khí tức bước thứ ba nhưng bất đồng với tu sĩ trong động phủ, lao thẳng tới tân tiên giới thôn phệ hương hỏa.","anchor":"Hắn đã đợi ngày này ba năm rồi","mucCt":"ky"},{"importance":"normal","mucCt":"ky","chuong":"@c1593","tieuDe":"Thân ảnh đuổi tiên nhân, kim quang huyết mạch trấn áp","text":"Bản thể ngồi ở giới ngoại Thái Cổ Tinh Thần, cảm nhận tiên nhân xâm nhập tiên giới. Qua ngọc giản giao Tư Đồ Nam ba năm trước, một tia thần thức huyễn hóa thành thân ảnh, quát hỏi Chu Tước, Huyền Vũ, Thanh Long, Bạch Hổ về ước định, phát sát lục kinh thiên đuổi hơn mười tiên nhân khỏi tiên giới. Nhận ra viễn cổ tiên vực giới ngoại cũng mở, lập tức vọt tới lỗ hổng tinh không, ý đồ lấy lực lượng hai cung hủy diệt viễn cổ tiên vực giới ngoại. Đối mặt đệ tử Thất Đạo Tông bay ra, một tiên nhân lao tới định hút thành hương hỏa. Mở bừng mắt phát kim quang từ giọt máu tiên nhân bất diệt thể, huyết mạch tinh thuần cực điểm, trấn áp tiên nhân khiến hắn hãi hùng lui lại hỏi “Ngươi là ai!”","anchor":"Kim quang này là giọt máu do tiên nhân bất diệt thể hóa thành được hắn ngưng tụ ra"},{"importance":"normal","mucCt":"ky","chuong":"@c1594","tieuDe":"Liên bắn hai mũi tên cung Lý Quảng, phong ấn viễn cổ tiên vực","text":"Lần đầu tiên liên tục bắn hai mũi tên kể từ khi có cung Lý Quảng. Mũi thứ nhất bành trướng mấy ngàn trượng, xuyên qua hình thần câu diệt, giết sạch hơn mười tiên nhân Thất Đạo Tông vừa ra khỏi viễn cổ tiên vực. Mũi thứ hai mang lực hút khổng lồ khiến lỗ hổng thông đạo co rút sụp đổ hoàn toàn, phong ấn viễn cổ tiên vực giới ngoại, ngăn chặn hai luồng khí tức mạnh ngang Chưởng Tôn từ bên trong lao ra. Kim quang huyết mạch tiên nhân trong hai mắt (đặc biệt mắt trái) tiêu tán hoàn toàn sau khi bắn, trán toát mồ hôi, tiêu hao cực lớn. Chưởng Tôn phong ấn toàn bộ Thái Cổ Tinh Thần nhốt Vương Lâm, cùng Thất phi, Diệu Âm đạo tôn, Cửu Thiên ma tôn đồng loạt lao tới giết.","anchor":"Đây là lần đầu tiên sau khi hắn có được cây cung của Lý Quảng liên tục bắn hai mũi tên"},{"chuong":"@c1595","importance":"normal","mucCt":"ky","tieuDe":"Thi triển Tộc Bất Diệt Chỉ nghênh chiến Chưởng Tôn","text":"Bị Chưởng Tôn tấn công ngay sau khi khai cung. Bình tĩnh nghênh chiến: kích hoạt Cổ Thần tinh điểm trên mi tâm và tinh điểm Cổ Yêu trong mắt trái, ngưng tụ toàn bộ lực lượng Đạo cổ lên ngón trỏ, lần đầu thi triển thần thông tự nghĩ ra — Tộc Bất Diệt Chỉ (lấy cảm hứng từ tiên nhân bất diệt thể). Đồng thời triển khai Thanh Quang Thuẫn, Quang Ảnh Thuẫn và Ngũ Thải hồ điệp. Nói câu «Còn chưa tới thời cơ» cho thấy đã có kế hoạch. Ngón trỏ đối đầu chưởng ấn trăm trượng huyền kiếp, bị hủy diệt và tái tạo hơn ngàn lần, thân thể nứt vỡ khắp nơi, phun máu. Quang Ảnh Thuẫn sụp đổ, Thanh Quang Thuẫn bị cuốn về thân, Ngũ Thải hồ điệp tiêu tan — ba lớp phòng ngự đều vỡ, chịu tổn thương nghiêm trọng trước khoảng cách tu vi quá lớn.","anchor":"tay phải Vương Lâm bỗng nhiên giơ lên, Cổ Thần tinh điểm trên mi tâm hắn tinh điểm cổ Yêu trong mắt trái hắn đều lóe sáng"},{"importance":"normal","mucCt":"ky","chuong":"@c1596","tieuDe":"Bắn tên thứ ba, đại phá bốn cường giả","text":"Bị Chưởng Tôn tung chưởng ấn huyền kiếp đánh trọng thương liên tiếp, lần lượt dùng Dịch Linh Ấn, trường thương bảy màu, sáu thanh kiếm bổn nguyên đối kháng đều không đủ sức. Lần đầu tiên thi triển thuật Tê Thiên (đoạt từ con trai Diệp Mịch), kết hợp hư ảnh thân thể Đạo Cổ (do tám giọt huyết quang chưa luyện hóa tự hiện ra — lần đầu hiện cả thân thể mơ hồ chứ không chỉ đầu lâu) xé tan chưởng ấn, bản thân bị trọng thương nặng. Hé lộ kế hoạch: hủy viễn cổ tiên vực giới ngoại, làm loạn động phủ, khiến các thế lực mất cân bằng — tất cả chỉ là bước đầu tiên, đã tính trước việc bị vây trong Thái Cổ Tinh Thần. Cố ý chờ bốn cường giả (Chưởng Tôn, Thất Phi, Diệu Âm Đạo Tôn, Cửu Thiên Ma Tôn) tụ tập rồi rút cung Lý Quảng bắn mũi tên thứ ba, hoàn toàn vượt ngoài dự liệu Chưởng Tôn. Nhắm mắt giấu ánh sáng vàng khi bắn. Mũi tên xuyên phá mọi thần thông Chưởng Tôn, xuyên thân khiến hắn tan xác bỏ trốn, đánh nổ tung Diệu Âm Đạo Tôn và Cửu Thiên Ma Tôn rồi bắt gọn nguyên thần cả hai, trọng thương Thất Phi.","anchor":"Hàn mang trong ánh mắt loé lên, trực tiếp nhắm hai mắt lại, không cho người khác nhìn thấy ánh sáng màu vàng trong mắt mình"},{"chuong":"@c1597","importance":"major","mucCt":"ky","tieuDe":"Thoát tinh không, gặp Phàn San Lộ nhận đề nghị","text":"Đạo nhân bảy màu hiện thân, Vương Lâm không chút do dự bóp nát ngọc giản do Phàn San Lộ đưa từ trước tạo hắc động, được ngọc thủ đệ nhất phi thi triển Thái Ngọc Thất Thủ Ấn chặn chỉ phong bảy màu, rồi bị hắc động hút vào thoát khỏi tinh không Thái Cổ Tinh Thần. Toàn bộ kế hoạch đường lui đã chuẩn bị từ một năm trước khi thôn nạp trong Vô Danh Chuyển Luân trận, lợi dụng ngọc giản liên lạc nữ tử đạt thành hiệp ước. Qua hắc động tới khe sâu Yêu Tông cũ (Vân Hải tinh vực), gặp Phàn San Lộ — đệ nhất phi, muội muội đạo lữ Thất Thải Thiên Tôn, đệ tử hạch tâm Đại Hồn Môn thuộc Cửu Vũ Thập Tam Môn. Nghe nàng đề nghị: giết Thất Thải Thiên Tôn đoạt sơn môn Thất Đạo Tông, rồi nhập Đại Hồn Môn qua Tiên Cương đại lục. Cuối cùng hỏi về số phận tu sĩ khác trong động phủ thì cả hai cùng biến sắc cảm ứng điều bất thường phía sau.","anchor":"Cho nên một năm trước khi hắn thôn nạp trong Vô Danh Chuyển Luân trận đã lợi dụng ngọc giản do nữ tử này đưa từ trước mà truyền thần niệm"},{"chuong":"@c1598","importance":"normal","mucCt":"ky","tieuDe":"Bị Thất Thải Tiên Tôn truy sát, kéo cung Lý Quảng phản kích","text":"Đạo nhân bảy màu xuất hiện truy sát đòi cung tên Lý Quảng, sóng âm từ lời nói khiến Vương Lâm phun máu. Quyết định không ẩn giấu thực lực, dùng giọt huyết mạch tiên nhân mà Chưởng Tôn không biết để kéo cung Lý Quảng bắn mũi tên va chạm chín hỏa điểu. Cùng Phàn San Lộ chạy trốn, bị tinh thể bảy màu vây khốn, Phàn San Lộ cầu viện tỷ tỷ phá vây. Ôm Phàn San Lộ kiệt sức na di tới động phủ thuyền tím của nàng, hỏi danh tính thật của đạo nhân bảy màu.","anchor":"Nhưng Chưởng Tôn lại không biết là trong tay Vương Lâm còn có một giọt huyết mạch tiên nhân nữa"},{"importance":"normal","mucCt":"ky","chuong":"@c1599","tieuDe":"Khảo sát chiến thuyền, phát hiện cơ hội cấm chế bổn nguyên","text":"Tản thần thức bao phủ toàn bộ chiến thuyền, nhận ra cả thuyền do cấm chế tạo thành như một trận pháp khổng lồ, nhận diện tứ đại cấm chế (Tuế Nguyệt, Sinh Tử, Phá Diệt) cùng nhiều cấm chế chưa từng thấy, nhận thấy nếu nắm giữ toàn bộ có khả năng đạt thành tựu cấm chế bổn nguyên. Bị mặt quỷ trên buồm phát tiếng gào thét xuyên tâm thần phải lùi lại. Nhận định cấm chế chỉ mở chưa tới hai phần, không đủ chặn đạo nhân bảy màu, quyết không giao cung Lý Quảng vì cần nó để đấu bậc toàn năng Không Huyền. Nhận ra nữ tử trên thuyền không phải Phàn San Lộ mà là Phàn San Mộng. Nghe Phàn San Mộng kể quá khứ nhưng chỉ tin một phần, phát hiện lời nàng có dấu vết.","anchor":"Lời nói của nữ tử này nhìn qua thì đều là những lời tâm huyết nhưng trên thực tế lại có chút dấu vết"},{"importance":"normal","mucCt":"ky","chuong":"@c1600","tieuDe":"Bí mật ba hồn bảy phách — suy luận chấn động","text":"Nghe nữ tử áo trắng tiết lộ bí mật ba hồn bảy phách của Thất Thải Thiên Tôn: hồn thứ nhất nắm thần thông chính là đạo nhân bảy màu, hồn thứ hai chứa ý cảnh và bổn nguyên lực, hồn thứ ba nắm toàn bộ trí nhớ và bí mật triệu hoán thiên đạo. Chấn động suy luận ra Chiến lão quỷ rất có thể chính là hồn thứ hai, giải thích vì sao Chưởng Tôn e sợ khi gặp lại Chiến lão quỷ. Nhận ra Thanh Thủy sư huynh chính là một trong thất phách, giải thích cuộc đời thê thảm và thực lực dị thường khi vừa vào bước thứ ba. Tự hỏi bản thân có phải là một trong thất phách hay không. Nghe nữ tử đề xuất hai phương pháp giết Thất Thải Thiên Tôn, trong đó phương pháp hai là dạy Vương Lâm thần thông thôn phệ hồn thứ ba rồi nuốt nốt hai hồn và thất phách để trở thành Thất Thải Thiên Tôn mới. Liên tưởng tới chuyện thánh tổ phù văn tộc bị Thanh Lâm trấn áp ở vùng đất Yêu Linh, cảnh giác trước lời nữ tử. Khi nữ tử đề nghị thệ huyết, nhận ra tất cả lời nàng chỉ là đánh lạc hướng có thâm ý riêng, thầm cười lạnh, chuyển hướng hỏi về tế đàn năm xưa.","anchor":"Tất cả những lời đối phương nói ra đều chỉ là đánh lạc hướng, hiển nhiên chỗ này có thâm ý riêng"},{"chuong":"@c1601","importance":"normal","mucCt":"ky","tieuDe":"Phản khách vi chủ — nghiên cứu cấm chế thuyền","text":"Nhìn thấu bố cục của hai tỷ muội Phàn San Mộng: cố tình trì hoãn để đạo nhân bảy màu đuổi tới, dụ hắn lên thuyền tạo thế cấp bách ép trao huyết thệ. Từ chối đề xuất phá tế đàn trong ba ngày, chọn nghiên cứu cấm chế chiếc thuyền nhằm phản khách vi chủ. Kích hoạt lực lượng Đạo cổ, dung hợp tinh điểm Cổ Thần mi tâm và sáu tinh điểm Cổ Yêu mắt trái thành hư ảnh Đạo cổ mấy chục trượng bảo vệ toàn thân. Phóng ra gần trăm vạn cấm chế hợp nhất thành một chưởng phá vỡ tầng phòng hộ cấm chế bên ngoài boong tàu. Phát hiện boong thuyền thực chất do cấm chế ngưng tụ mà thành, bắt đầu phân tích ký hiệu cấm chế, nhận định thời gian ba ngày hơi gấp.","anchor":"Nếu hắn thật sự có thể nghiên cứu được chiếc thuyền này, nắm được cách điều khiển như vậy chẳng những có thể giải được nguy cơ bên ngoài từ đạo nhân bảy màu mà hoàn toàn có thể phản khách vi chủ"},{"importance":"normal","mucCt":"ky","chuong":"@c1602","tieuDe":"Lĩnh ngộ Cổ Hồn cấm, đoạt quyền kiểm soát thuyền cổ","text":"Tĩnh tâm nghiên cứu cấm chế trên boong thuyền cổ của Phàn San Mộng, đối mặt với mặt quỷ yêu dị trên cánh buồm nửa ngày mới bình tĩnh lại. Dành năm canh giờ nghiên cứu hoàn toàn một Cổ Hồn cấm đầy đủ trên boong thuyền, từ đó lĩnh ngộ toàn bộ nguyên lý loại cấm chế thứ tư trong tứ đại cấm — trước đó chỉ biết phiên bản có khuyết điểm. Sau khi lĩnh ngộ, phá hủy và thay thế toàn bộ mấy ngàn vạn cấm chế trên boong tàu (tầng một) trong thời gian cực ngắn, đoạt quyền điều khiển tầng thứ nhất. Ghi nhớ một số cấm chế kỳ dị chưa từng thấy ngoài tứ đại cấm để nghiên cứu sau. Tiến xuống tầng thứ hai, dùng bảy canh giờ phá xong, đoạt thêm quyền kiểm soát thuyền. Tiết lộ thuyền có tổng cộng chín tầng cấm chế. Lúc này quyền kiểm soát của Phàn San Mộng chỉ còn nhiều hơn hắn một chút.","anchor":"Với khả năng minh ngộ của hắn, dùng năm canh giờ là đủ để hiểu hết cấm chế này"},{"chuong":"@c1603","importance":"major","mucCt":"ky","tieuDe":"Vạch trần Phàn San Lộ giả dạng, tứ đại cấm chế viên mãn","text":"Khi Phàn San Mộng mở phòng hộ cho đạo nhân bảy màu lên thuyền gây sức ép, Vương Lâm chủ động hủy cấm chế tầng một cho đối phương tiến vào tầng hai, dùng ngược lại làm đòn bẩy uy hiếp. Ép Phàn San Mộng trì hoãn đạo nhân bảy màu, tranh thủ ba canh giờ nghiên cứu cấm chế tầng ba — hơn phân nửa chưa từng gặp, khiến trình độ tăng vọt. Tứ đại cấm chế đạt viên mãn, chỉ thiếu dung hợp làm một sinh bổn nguyên. Sau hai canh giờ tầng hai sụp đổ, hắn kịp biến cấm chế tầng ba thành lưới chắn, cùng Phàn San Mộng tiến vào tầng bốn. Tại đây vạch trần nữ tử đồng hành thực ra là Phàn San Lộ giả dạng từ đầu bằng cách phun máu biến hóa thần sắc khí tức. Tuyên bố toàn bộ tầng hai đến tầng bốn và đạo nhân bảy màu trên thuyền đều là huyễn giới do Phàn San Lộ tạo ra. Chủ động đánh sập tầng ba để kiểm chứng.","anchor":"tứ đại cấm chế của Vương Lâm đã đạt tới viên mãn chỉ thiếu việc dung hợp làm một, sinh ra bổn nguyên"},{"chuong":"@c1604","importance":"normal","mucCt":"ky","tieuDe":"Phá Đại Hồn chân ảo thuật, chiếm buồm mặt quỷ","text":"Bị cuốn vào ảo thuật huyễn cảnh song trọng của Phàn San Mộng thi triển từ xa mà không hay biết, toàn bộ cảnh trên thuyền đều là huyễn giới. Trong ảo cảnh bình tĩnh đối mặt vầng mặt trời của đạo nhân bảy màu giả, nhận ra tất cả đều là giả rồi vung tay tiêu tán mọi huyễn tượng, thức tỉnh trên boong tàu tầng nhất. Phân tích mưu kế tầng tầng lớp lớp của hai chị em Phàn San cho Phàn San Lộ nghe. Suy luận Phàn San Mộng chưa từng bị Thất Thải Tiên Tôn giết chết, rất có thể dùng ảo thuật lừa gạt hắn, thậm chí mối quan hệ đạo lữ năm đó cũng chưa chắc thật. Đánh giá Phàn San Mộng là người thứ hai cả đời khiến hắn kiêng kỵ trong lòng. Hung hăng giật cánh buồm có khuôn mặt quỷ trên thuyền, tuyên bố chiếm bảo vật này, khiến Phàn San Mộng ở Tiên Cương đại lục phun máu kinh hãi.","anchor":"cả đời gặp vô số người, chỉ có một người là ta cảm thấy thần bí khó lường, trong lòng kiêng kỵ. Lúc này lại có thêm một người đó là tỷ tỷ của ngươi"},{"chuong":"@c1605","importance":"major","mucCt":"ky","tieuDe":"Thu buồm mặt quỷ, hứa đưa Phàn San Lộ về nhà, thử xâm nhập ảo giác đạo nhân bảy màu","text":"Thu tấm buồm mặt quỷ (pháp bảo Đại Hồn Môn, chủ hồn trên thuyền) cùng chiếc thuyền làm bồi thường cho việc bị lừa, bắt đầu luyện hóa trong không gian trữ vật để nắm cấm chế điều khiển thuyền. Nhận ngọc giản chứa bản đồ dẫn tới tế đàn và thuật thôn hồn người thứ ba từ Phàn San Lộ. Nhận thệ huyết của nàng (máu đỏ chuyển vàng) dung nhập vào cơ thể, hứa mang nàng về Tiên Cương đại lục — lời hứa đầu tiên sau khi đạt tu vi bước thứ ba. Tự đánh giá tu vi không bằng bậc toàn năng Không Huyền, cần tới tế đàn tìm cơ duyên và lợi dụng đại chiến viễn cổ tiên vực sắp tới. Phát hiện đạo nhân bảy màu đang chìm đắm trong ảo giác trên thi hài mãnh thú, xung quanh có cấm chế hủy diệt vô thanh trong phạm vi trăm trượng. Quyết định liều lĩnh tiến vào, thi triển Mộng Đạo thuật cố xâm nhập ảo giác đạo nhân bảy màu nhưng thất bại, khóe miệng tràn máu, không cam lòng.","anchor":"Vương Lâm nhíu mày, thần sắc lộ vẻ không cam lòng"},{"importance":"normal","mucCt":"ky","chuong":"@c1606","tieuDe":"Thâm nhập ký ức Thất Thải Tiên Tôn","text":"Cắn lưỡi phun 99 giọt máu tươi chứa tu vi toàn thân, dung hợp Đạo Cổ bất diệt vào một giọt kèm tia nguyên thần để thâm nhập vùng uy áp kinh khiếp của đạo nhân bảy màu. 98 giọt hình thành quầng sáng bảo vệ bị tiêu tán, giọt Đạo Cổ bị hủy diệt–khôi phục vô số lần, cuối cùng chỉ còn tia máu kịp rơi vào mi tâm đạo nhân rồi tan biến, nhưng nguyên thần kịp chạm thân thể đối phương. Thi triển Mộng Đạo, tâm thần sụp đổ, bị cuốn vào huyễn cảnh bảy màu, phát hiện đạo nhân ngồi thẫn thờ trên núi nhắc tên Phàn San Mộng, suy đoán đây là huyễn trong huyễn. Lấy buồm mặt quỷ tung phủ thân, nguyên thần phá hư vô bay tới đạo nhân, mặt quỷ hóa khuôn mặt Vương Lâm rơi vào mắt đạo nhân như hố đen, bị hút vào tầng ký ức sâu. Chứng kiến toàn bộ đại chiến năm xưa giữa Thất Thải Tiên Tôn và liên minh Liên Đạo Phi, Phàn San Mộng, Phàn San Lộ. Thấy Tiên Tôn bị phản bội, triệu Thiên Đạo đồng quy vu tận, thân thể vỡ thành ba phần: đạo nhân bảy màu, ý cảnh, trí nhớ hóa cầu vồng. Hiểu ra nguyên nhân đạo nhân bảy màu cam tâm chìm trong ảo giác — hắn đang cố lấy lại phần hồn thứ ba chứa toàn bộ trí nhớ.","anchor":"Hắn đã hiểu rồi, đã hiểu tại sao đạo nhân bảy màu lại cam tâm chìm đắm trong ảo giác này mà không muốn thức tỉnh!"},{"importance":"normal","mucCt":"ky","chuong":"@c1607","tieuDe":"Rống Đạo cổ đánh thức đạo nhân bảy màu","text":"Nhận ra đạo nhân bảy màu lợi dụng ảo giác Phàn San Mộng sửa thành cảnh quay ngược thời gian để truy tìm hồn thứ ba — nếu tìm được thì Vương Lâm chắc chắn chết. Ba lần phun nguyên thần khí (quý hơn tinh huyết) tăng tốc gấp trăm lần đuổi kịp đạo nhân bảy màu trong huyễn cảnh tầng hai, nguyên thần đau đớn như bị thiêu đốt xé rách. Tận mắt thấy hồn thứ ba bay vào giới nội rồi xuyên Vân Hải tinh vực hướng Triệu Hà. Nhận định tu vi không đủ ngăn đối phương trong tầng hai, dùng tấm buồm mặt quỷ thoát về huyễn cảnh tầng một. Bị quang nhiệt chín hỏa điểu chặn không tiếp cận được thân thể thật đạo nhân bảy màu, tóc bốc cháy tiêu tán. Nghĩ ra kế dùng lục đại bổn nguyên ngưng tụ thành chiếc loa phóng đại âm thanh, kết hợp Đạo cổ lực (dung hợp tam tộc cổ) rống một tiếng kinh thiên — thần thông học từ trận đẩy lui Chưởng Tôn ở cổ mộ — khiến thiên không sụp đổ, đại địa nứt vỡ, phong vân biến sắc.","anchor":"Một tiếng rống này là tiếng rống của Cổ Thần, là tiếng rống của Đạo cổ, cũng là thần thông khi ở vùng đất cổ mộ Vương Lâm đẩy lui Chưởng Tôn mà học được"},{"importance":"normal","mucCt":"ky","chuong":"@c1608","tieuDe":"Phá huyễn cảnh đạo nhân bảy màu, bỏ trốn hướng tế đàn","text":"Dùng lục đại bổn nguyên biến thành loa khuếch đại tiếng rống, xuyên qua chín mặt trời bảo vệ, phá tan huyễn cảnh tầng hai của đạo nhân bảy màu, cắt đứt việc truy tìm hồn thứ ba. Bị phản kích từ tiếng gào phẫn nộ của đạo nhân bảy màu, lục đại bổn nguyên sụp đổ, phun máu nhiều lần, gần xương tan thịt nát. Nhờ Đạo cổ bất diệt nhanh chóng khôi phục, vung tấm buồm mặt quỷ che thân rồi dùng huyết độn điên cuồng bỏ trốn. Xác định tế đàn là sinh cơ duy nhất sau khi dung nhập hồn phách Thiên Vận Tử bói toán.","anchor":"Phá hoại kế hoạch của đối phương là việc hắn phải làm!"}],"tuiDo":{"phapBao":[{"ten":"Thanh Quang Thuẫn","trangThai":"dang-co","moTa":"Đã chữa trị đầy đủ, truyền lực lượng Đạo Cổ vào kích hoạt Mộng Hồi Viễn Cổ bên trong.","nguon":"@c1579"}]},"nhanMach":[{"ten":"Hồng Điệp","tag":"ban-be","quanHe":"Nữ tử kính nể Vương Lâm, có tình cảm không rõ ràng; từng giao chiến ở Vũ Tiên Giới, được Vương Lâm giải thoát khỏi luân hồi ở Chu Tước mạc","ghiChu":"Xác nhận danh tính @c1581"},{"ten":"Diệu Âm đạo tôn","tag":"doi-thu","quanHe":"Kẻ địch, từng bị Vương Lâm nhốt trong cổ mộ, được Chưởng Tôn cứu ra tấn công hắn"},{"ten":"Cửu Thiên ma tôn","tag":"doi-thu","quanHe":"Kẻ địch, từng bị Vương Lâm nhốt trong cổ mộ, cùng Diệu Âm và Đại Hoang tấn công hắn"},{"ten":"Đại Hoang Thượng Nhân","tag":"doi-thu","quanHe":"Kẻ địch, từng bị Vương Lâm nhốt trong cổ mộ, cùng hai người kia tấn công hắn"},{"ten":"Chưởng môn phân tông Quy Nhất tông","tag":"khac","quanHe":"Chưởng môn phân tông nhận ra huyết kiếm là kiếm của Diệp Mịch","ghiChu":"@c1586"},{"ten":"Viêm long","tag":"khac","quanHe":"Linh thú thu phục, trước đây là thú cưỡi của Liên Đạo Phi","ghiChu":"Dùng ấn quyết Chu Tước trấn áp, thu vào khe trữ vật @c1591"},{"ten":"Phàn San Lộ","tag":"dong-minh","quanHe":"Đồng minh hợp tác","ghiChu":"Đệ nhất phi Thất Đạo Tông, đề nghị Vương Lâm giết Thất Thải Thiên Tôn đổi sơn môn, hứa giúp nhập Đại Hồn Môn và qua kiếp nạn Tiên Cương"},{"ten":"Phàn San Mộng","tag":"doi-thu","quanHe":"Đối thủ tiềm tàng","ghiChu":"Người thứ hai cả đời khiến Vương Lâm kiêng kỵ trong lòng, thi triển ảo thuật suýt ép hắn giao thệ huyết"},{"ten":"Nữ tử trong băng sơn","tag":"khac","quanHe":"Tỷ tỷ của Phàn San Lộ, gián tiếp trợ lực phá vây cho Vương Lâm","ghiChu":"Truyền lực xuyên không gian từ Tiên Cương đại lục @c1598"}],"tuViMoc":[{"chuong":"@c1603","canhGioi":"Tứ đại cấm chế viên mãn","text":"Liên tục phá cấm chế trên thuyền, tứ đại cấm chế đạt viên mãn, chỉ thiếu dung hợp làm một sinh ra bổn nguyên.","importance":"major"}]},"nguon":["@c1579","@c1580","@c1581","@c1582","@c1583","@c1584","@c1585","@c1586","@c1587","@c1588","@c1589","@c1590","@c1591","@c1592","@c1593","@c1594","@c1595","@c1596","@c1597","@c1598","@c1599","@c1600","@c1601","@c1602","@c1603","@c1604","@c1605","@c1606","@c1607","@c1608"],"cn":"王林","gioiTinh":"nam","tinhCach":[]},{"id":"con-trai-diep-mich","name":"Con trai Diệp Mịch","cn":"","aliases":["nam tử trung niên"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Con trai của Đạo Cổ Diệp Mịch, được phụ tổ truyền thừa thuật Tê Thiên cực mạnh. Có thể triệu hồi hư ảnh tam tộc cổ và hư ảnh Đạo Cổ chiến đấu, rơi vào điên cuồng bất chấp sinh tử khi giao chiến với Vương Lâm.","vaiTro":"Đối thủ sinh tử của Vương Lâm, con trai Đạo Cổ Diệp Mịch","tinhCach":"Hung hãn quyết liệt; điên cuồng bất chấp sinh tử khi chiến đấu; kiêu ngạo tự phụ về truyền thừa của phụ tổ","tabs":{"diem":[{"text":"Được Đạo Cổ Diệp Mịch truyền thừa thuật Tê Thiên, thần thông lấy vạn vật làm trời, hai tay cổ tộc xé trời.","chuong":"@c1579"},{"text":"Khi chiến đấu rơi vào trạng thái điên cuồng bất chấp sinh tử, chỉ có ý niệm duy nhất muốn xé tan đối thủ.","chuong":"@c1579"}],"kinhLich":[{"mucCt":"ky","text":"Triệu hồi hư ảnh tam tộc cổ và hư ảnh Đạo Cổ Diệp Mịch tấn công Vương Lâm. Va chạm lần đầu bị vỡ hư ảnh tam tộc cổ, phun máu bị đẩy lùi. Thi triển thuật Tinh không là thiên vặn vẹo tinh không, rồi triển khai Tê Thiên xé đôi bàn chân khổng lồ, xuyên phá Mộng Hồi Viễn Cổ, xé rách thân thể Vương Lâm từ mi tâm tới bụng lộ xương. Rơi vào trạng thái điên cuồng bất chấp sinh tử, chỉ có ý niệm duy nhất muốn xé tan Vương Lâm.","anchor":"giờ phút này chỉ có một ý niệm duy nhất trong đầu là muốn xé tan thân thể Vương Lâm","bridge":true,"khoang":"@c1579"},{"importance":"normal","mucCt":"ky","chuong":"@c1580","tieuDe":"Bị Vương Lâm giết trong Mộng đạo","text":"Trong mộng, phát hiện nơi giao chiến chỉ là mắt trái của khuôn mặt khổng lồ Vương Lâm, kinh hoàng gào thét chống cự nhưng song chưởng vỡ tung, bị thiên địa nghiền nát. Mộng tỉnh vẫn đang mê mang giữa không trung, bị Vương Lâm dùng huyết kiếm chém đôi. Thân thể hóa thành tám giọt máu tím chui vào mi tâm Vương Lâm. Tử vong.","anchor":"Cho tới khi tử vong hai mắt hắn vẫn lộ vẻ mờ mịt vô tận"}],"tuViMoc":[],"nhanMach":[{"ten":"Diệp Mịch","tag":"su-mon","quanHe":"Phụ tổ (cha/tổ tiên)","ghiChu":"Được Diệp Mịch truyền thừa thuật Tê Thiên"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ sinh tử","ghiChu":"Giao chiến dữ dội tại tinh không bên ngoài Vô Danh Chuyển Luân trận"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Tê Thiên","moTa":"Thần thông cực mạnh do phụ tổ Diệp Mịch truyền thừa, lấy vạn vật làm trời, hai tay cổ tộc xé trời.","nguon":"@c1579"},{"ten":"Tinh không là thiên","moTa":"Thuật pháp vặn vẹo tinh không, dùng trước khi triển khai Tê Thiên.","nguon":"@c1579"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1579","@c1580"]},{"id":"diep-mich","name":"Diệp Mịch","tabs":{"kinhLich":[{"chuong":"@c1579","importance":"bridge","mucCt":"gon","text":"Đầu lâu Đạo Cổ Diệp Mịch được Vương Lâm dung hợp làm phương tiện chiến đấu; thuật Tê Thiên do hắn truyền thừa cho con trai được thi triển trong trận.","anchor":"Phụ tổ truyền thừa cho ta một thuật cực mạnh"},{"chuong":"@c1586","importance":"normal","mucCt":"vua","tieuDe":"Huyết kiếm xuyên tới Tiên Cương","text":"Huyết kiếm mang danh tính Diệp Mịch xuyên qua Đông Đan chung của Quy Nhất tông trên Tiên Cương. Tu sĩ Quy Nhất tông xác nhận lời đồn Diệp Mịch bị Thất Đạo Tông dẫn vào động phủ là thật.","anchor":"xem ra lời đồn Diệp Mịch đã bị Thất Đạo Tông dẫn vào động phủ là thật rồi"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1579","@c1586"],"trangThai":"khong-ro","cn":"叶覔","gioiTinh":"nam"},{"id":"tay-tu-phuong","name":"Tây Tử Phượng","cn":"西子凤","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"mucCt":"vua","text":"Ở bên cạnh Vương Lâm trong Vô Danh Chuyển Luân trận, lo lắng khi trận pháp bị tấn công. Ấm rượu đợi Vương Lâm suốt chín tháng nhưng hắn không uống. Hết một năm, thần sắc phức tạp nhìn Vương Lâm, than nhẹ rồi rời đi.","anchor":"Cho tới hết một năm, Tây Tử Phượng với thần sắc phức tạp nhìn Vương Lâm một lần, than nhẹ rồi từ từ rời đi","bridge":true,"khoang":"@c1580"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1580","@c1581"]},{"id":"chuong-ton","name":"Chưởng Tôn","cn":"掌尊","gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1580","text":"Xuất hiện ngoài trận pháp hơn trăm trượng, bị Vương Lâm kéo cung Lý Quảng uy hiếp, trầm mặc hồi lâu rồi xoay người rời đi.","anchor":"Lúc này thân ảnh Chưởng Tôn xuất hiện, nhìn chằm chằm vào Vương Lâm, trầm mặc hồi lâu rồi xoay người rời đi"},{"mucCt":"gon","text":"Hai năm trước tìm Lam Mộng Đạo Tôn hứa giúp tách hồn ngũ phi nhưng Lam Mộng biết bất khả. Cứu Diệu Âm đạo tôn, Cửu Thiên ma tôn và Đại Hoang Thượng Nhân ra khỏi cổ mộ nơi Vương Lâm nhốt, ba người mang sát khí lao tới tấn công Vương Lâm.","anchor":"Chưởng Tôn hai năm trước đi tìm ta, từng nói có thể giúp ta bức hồn phách ngũ phi trong thân thể thê tử ta ra","bridge":true,"khoang":"@c1582"},{"mucCt":"vua","text":"Ngồi trong cung điện cảm nhận Vương Lâm xuất hiện trong Thái Cổ Tinh Thần, nắm chặt bàn tay khô héo trầm mặc rất lâu. Dù tu vi thông thiên nhưng không dám hạ quyết tâm giết Vương Lâm vì kiêng kỵ cung Lý Quảng còn chưa dùng hết sức bắn hai cung, nghi ngờ Vương Lâm đang khiêu khích dụ hắn ra ngoài.","anchor":"Tu vi của hắn thông thiên, nếu không phải sợ cây cung của Lý Quảng thì sẽ lập tức ra tay giết người","bridge":true,"khoang":"@c1589"},{"mucCt":"vua","text":"Nhận ra Vương Lâm muốn lấy lực lượng hai cung hủy diệt viễn cổ tiên vực giới ngoại, gọi Vương Lâm là “điên cuồng”. Sắc mặt đại biến, bay vào tinh không.","anchor":"Hắn không ngờ muốn lấy lực lượng hai cung kia hủy diệt viễn cổ tiên vực của giới ngoại ta","bridge":true,"khoang":"@c1593"},{"mucCt":"vua","text":"Ở cách ngàn vạn dặm cảm nhận Vương Lâm bắn tên, vui mừng vì đánh giá Vương Lâm chỉ còn lực lượng hai cung và đã lãng phí hết. Lập tức phong ấn toàn bộ Thái Cổ Tinh Thần chỉ ngăn ra không ngăn vào, rồi lao đến chỗ Vương Lâm với sát khí nồng đậm.","anchor":"Ta tính hắn chỉ còn lực lượng bắn hai cung, giờ đã lãng phí một lần, còn một lần nữa thì hôm nay hắn hẳn phải chết","bridge":true,"khoang":"@c1594"},{"chuong":"@c1595","importance":"normal","mucCt":"ky","tieuDe":"Xuất thủ lần thứ sáu — chưởng ấn huyền kiếp","text":"Chờ đúng thời cơ Vương Lâm bắn xong hai mũi tên hết lực lượng huyết mạch tiên nhân, tu vi huyền kiếp bạo phát xuất hiện trong tinh vực. Hồi tưởng toàn bộ quá khứ: ba lần chật vật (bị đạo nhân bảy màu bắt bái sư, thua Chiến Không Liệt tại Thái Cổ Tinh Thần, bị trọng thương khi tìm mũi tên Lý Quảng) và năm lần đối đầu Vương Lâm đều thất bại hoặc ngoài ý muốn. Tự nhắc lại thân phận nô tài người điên, ngoài nhìn vào là môn hạ vương hầu, ở giới ngoại có Trường Tôn hội được vô số tộc lạc kính sợ. Xác định Vương Lâm chỉ còn lực lượng bắn hai mũi tên và cả hai đã bắn. Không nói một câu, trực tiếp đánh chưởng ấn trăm trượng về phía Vương Lâm. Nội tâm mơ hồ lo lắng dù miệng tự trấn an, chính thức coi Vương Lâm là khắc tinh sau năm lần thất bại.","anchor":"Vương Lâm giống như một cái dầm đâm thật sâu vào trong lòng Chưởng Tôn"},{"importance":"normal","mucCt":"ky","chuong":"@c1596","tieuDe":"Bị xuyên thân, đạo tâm sụp đổ bỏ trốn","text":"Tung chưởng ấn huyền kiếp liên tục đánh Vương Lâm, xác định đối phương chỉ bắn được hai tên cung Lý Quảng nên tự tin tiến tới cùng Thất Phi, Diệu Âm Đạo Tôn, Cửu Thiên Ma Tôn vây sát. Khi thấy Vương Lâm giương cung lần ba, đạo tâm bị rung chuyển dữ dội, kế hoạch hoàn toàn sụp đổ. Phát điên tung chưởng ấn, biến hóa giếng khổng lồ dung nạp tinh không, mặt trời đỏ đậm chứa quy tắc thái sơ, bức ra cốt châu tỏa bạch cốt khí tức tăng tu vi mấy lần quyết cược. Bị mũi tên xuyên thân, tan xác nhưng ngưng tụ sống lại, hoảng sợ chưa từng thấy, điên cuồng bỏ trốn không quay đầu.","anchor":"Không chút do dự, giống như ba năm trước, Chưởng Tôn điên cuồng bỏ trốn, không quay đầu một lần"},{"chuong":"@c1597","importance":"normal","mucCt":"vua","tieuDe":"Nhận ra đệ nhất phi qua ấn quyết","text":"Đang định bỏ chạy khi ánh sáng bảy màu hiện ra, lộ vẻ khổ sở. Nhận ra ấn quyết Thái Ngọc Thất Thủ Ấn từ ngọc thủ trong hắc động, kinh hãi xác nhận biết thân phận chủ nhân bàn tay.","anchor":"Hoá ra là nàng!"},{"importance":"bridge","mucCt":"gon","chuong":"@c1600","tieuDe":"","text":"Được nhắc: bị đạo nhân bảy màu thu phục làm sai vặt, chiếm cứ giới ngoại.","anchor":"cũng thu phục gã sai vặt Chưởng Tôn, chiếm cứ giới ngoại"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1580","@c1582","@c1589","@c1593","@c1594","@c1595","@c1596","@c1597","@c1598","@c1600"],"canhGioiCaoNhat":"Huyền Kiếp"},{"id":"moc-bang-mi","name":"Mộc Băng Mi","cn":"木冰眉","gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1580","text":"Ở trong giới nội cùng nữ tử áo hồng, thấp thỏm lo lắng cho Vương Lâm.","anchor":"bên trong giới nội, Mộc Băng Mi và nữ tử áo hồng kia đang thấp thỏm"},{"importance":"bridge","mucCt":"vua","chuong":"@c1582","text":"Ngày cuối năm thứ hai tới bên cạnh Vương Lâm, bình thản ngồi xuống không nói gì, gật đầu chào Lý Thiến Mai rồi nhắm mắt.","anchor":"Mộc Băng Mi đi tới bên cạnh Vương Lâm. Nàng không có nói bất cứ điều gì mà chỉ bình thản ngồi bên cạnh hắn"},{"chuong":"@c1583","importance":"bridge","tieuDe":"Chứng kiến Vương Lâm tiếp nhận Lý Thiến Mai","text":"Chứng kiến Vương Lâm và Lý Thiến Mai đoạn tuyệt rồi tiếp nhận, mi tâm mơ hồ đau đớn dù cho rằng mình không có tư cách khuyên can.","anchor":"Nhìn phụ thân của con trai mình và một người phụ nữ khác đoạn tuyệt, chuyện này không ngờ lại khiến mi tâm của Mộc Băng Mi mơ hồ đau đớn"},{"mucCt":"ky","text":"Ở lại trong Vô Danh Chuyển Luân trận cùng Vương Lâm suốt gần một năm, muốn mở miệng nói chuyện nhưng Vương Lâm nhắm mắt tham ngộ thuật Tê Thiên nên đành nuốt lời. Khi chỉ còn một tháng cuối, nàng nói câu duy nhất trong cả năm — Bảo trọng — rồi xoay người về Côn Hư. Tâm trạng cô độc, hâm mộ Lý Thiến Mai có phụ thân, Lý Mộ Uyển có Vương Lâm, còn nàng không gia đình, không sư tôn, người quen đều đã chết, chỉ còn Vương Bình nhưng Bình nhi hận nàng.","anchor":"Đây là câu nói đầu tiên trong một năm qua của nàng, cũng là câu nói cuối cùng.","bridge":true,"khoang":"@c1584"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1580","@c1581","@c1582","@c1583","@c1584"]},{"id":"hong-diep","name":"Hồng Điệp","cn":"红蝶","aliases":["Phấn y nữ tử","nữ tử áo hồng"],"gioiTinh":"nu","trangThai":"song","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1580","text":"Ở trong giới nội thấp thỏm cùng Mộc Băng Mi; sau khi Tây Tử Phượng rời đi, nàng ở bên cạnh Vương Lâm trên mặt đất.","anchor":"Trên mặt đất, lúc này bên cạnh Vương Lâm là nữ tử áo hồng"},{"importance":"normal","mucCt":"ky","chuong":"@c1582","tieuDe":"Phát hiện mối liên hệ Thanh Thủy — đại nho đặt tên","text":"Ngày cuối năm thứ hai từ biệt Vương Lâm để trở về chỗ Mộc Băng Mi. Trước khi đi, tiết lộ sư tôn năm xưa từng gặp một đại nho họ Vương, người chỉ điểm trận pháp cho sư tôn và đặt tên cho nàng là Hồng Điệp. Hỏi Vương Lâm về Thanh Thủy có thân nhân không. Nghe Vương Lâm kể nữ nhi duy nhất của Thanh Thủy đã luân hồi, trên vai trái có thai ký màu hồng không bao giờ tiêu tán, nàng thân thể lảo đảo, sắc mặt tái nhợt, nói cảm tạ rồi hóa cầu vồng lao về La Thiên với tốc độ nhanh nhất muốn gặp Thanh Thủy.","anchor":"Sư tôn từng nói năm đó bà gặp một đại nho họ Vương, khi đó ta vốn không thể sống sót"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Kính nể, có tình cảm không rõ ràng; từng giao chiến ở Vũ Tiên Giới, được Vương Lâm giải thoát ở Chu Tước mạc","ghiChu":"Xác nhận danh tính, hàn huyên @c1581"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1580","@c1581","@c1582"]},{"id":"ly-thien-mai","name":"Lý Thiến Mai","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c1582","text":"Ngồi gần Vương Lâm, khi nghe hắn nói đã có thê tử thì cúi đầu che giấu thần sắc ảm đạm.","anchor":"vị trí hơi xảo diệu, khá gần Vương Lâm mơ hồ giống như là một người vợ cạnh chồng"},{"chuong":"@c1583","importance":"normal","tieuDe":"Được Vương Lâm tiếp nhận","text":"Lo lắng theo dõi phụ thân chiến đấu ba ngày, rơi nước mắt khi hiểu được hy sinh của cha. Muốn cùng cha về nhà không đi đâu nữa. Xin Vương Lâm tặng lại bức tranh sơn thủy năm xưa, nói lời đoạn tuyệt phân biệt ân không phải tình. Cuối cùng được Vương Lâm hủy tranh tiếp nhận, vùi đầu khóc ròng trong lòng hắn.","anchor":"Vương Lâm, ân, không phải là tình"},{"importance":"normal","mucCt":"vua","chuong":"@c1584","tieuDe":"Cùng phụ thân trở về Lam Ti tộc","text":"Cùng phụ thân Lam Mộng Đạo Tôn mang ngũ phi trở về Lam Ti tộc, dự định lần sau mang cả tộc vào giới nội lập tân tộc. Ra đi vui vẻ, thỉnh thoảng quay đầu nhìn Vương Lâm với ánh mắt ôn nhu, khẳng định dù có chết cũng không hối hận về lựa chọn của mình.","anchor":"Nam tử này chính là người nàng lựa chọn, trước kia nàng không hối hận"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1581","@c1582","@c1583","@c1584"],"canhGioiCaoNhat":"Không rõ","trangThai":"song","cn":"李芊梅","gioiTinh":"nu"},{"id":"lam-mong-dao-ton","name":"Lam Mộng Đạo Tôn","cn":"蓝梦道尊","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lam Ti Tộc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền đỉnh phong (@c1582)","trangThai":"song","blurb":"Thái cổ ngũ tôn, phụ thân của Lý Thiến Mai, tộc trưởng Lam Ti Tộc. Sau gần hai năm suy tư, chủ động tìm đến Vương Lâm đề nghị liên minh hôn nhân, sẵn sàng mang cả Lam Ti Tộc gia nhập giới nội.","vaiTro":"Phụ thân Lý Thiến Mai, tộc trưởng Lam Ti Tộc, thái cổ ngũ tôn","tinhCach":"Trầm tư sâu sắc; coi trọng gia đình; biết nhìn nhận lại sai lầm; quyết đoán khi đã suy tính xong","tabs":{"diem":[{"text":"Thái cổ ngũ tôn, một trong những cường giả đỉnh phong, sẵn sàng quét sạch đường phía trước cho con rể","chuong":"@c1581"},{"text":"Từng nhìn lầm Vương Lâm, ra tay trong Huyễn Chân đại trận vì bản thân và con gái, sau gần hai năm thay đổi thái độ","chuong":"@c1581"},{"text":"Tu vi Không Huyền đỉnh phong, có thể chủ động dẫn động huyền kiếp khiến Chưởng Tôn cũng phải tránh.","chuong":"@c1584"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1582","tieuDe":"Tuyên bố đứng về phía Vương Lâm — kể bí mật ngũ phi","text":"Đề nghị Lý Thiến Mai làm thê tử thứ hai của Vương Lâm, không ép. Tiết lộ bản thân là người sinh ra trong giới nội thứ hai sau Chiến lão quỷ, tu vi Không Huyền đỉnh phong, sớm có thể bước vào huyền kiếp. Kể rằng thê tử bị ngũ phi (một trong bát phi Tiên Tôn, đang bị phong ấn trong Thiên Hoàng Lô của Vương Lâm) đoạt xá, hồn phách dung hợp hoàn toàn không thể tách, một chết cả hai chết. Chưởng Tôn từng tới hứa giúp tách hồn phách nhưng Lam Mộng biết điều đó bất khả. Tuyên bố không đánh Vương Lâm nữa, sẵn lòng liên thủ chống Đạo nhân Bảy Màu và Chiến lão quỷ. Chủ động bước ra chặn ba kẻ địch Diệu Âm, Cửu Thiên, Đại Hoang, tung khí tức Không Huyền đỉnh phong khiến tinh không run rẩy.","anchor":"Hồn phách của thê tử ta sớm đã hoàn toàn dung hợp với ngũ phi. Các nàng căn bản là không thể chia lìa nữa"},{"chuong":"@c1583","importance":"major","tieuDe":"Một đánh ba và tự xưng thái cổ ngũ tôn","text":"Lam Mộng Đạo Tôn một mình đánh bại Diệu Âm Đạo Tôn, Cửu Thiên và Đại Hoang Thượng Nhân trong ba ngày. Diệu Âm trọng thương rớt xuống Không Linh, Cửu Thiên mất hương hỏa giới tâm thần tổn thương, Đại Hoang bỏ chạy sống không quá mười năm. Tự xưng là một trong thái cổ ngũ tôn, sinh ra từ thái cổ, khẳng định mọi việc đều vì con gái, không tham gia cuộc chiến giới nội giới ngoại. Đặt điều kiện cuối cho Vương Lâm: nếu Lý Mộ Uyển sống lại thì kết huynh muội với Thiến Mai, nếu không thì phải thành đạo lữ. Thấy con gái hết hy vọng, từ tức giận hóa bi ai.","anchor":"Ta chỉ muốn bảo vệ cho Lam Ti tộc, dù ai là kẻ thắng cuối cùng thì cũng chẳng liên quan tới ta"},{"mucCt":"vua","text":"Mang Lý Thiến Mai và ngũ phi trở về Lam Ti tộc, dự định lần sau mang cả tộc vào giới nội lập tân tộc. Dù bị thương nhưng tu vi Không Huyền đỉnh phong vẫn đủ bảo đảm an toàn trên đường, hắn có thể dẫn động huyền kiếp khiến Chưởng Tôn cũng phải tránh.","anchor":"tu vi Không Huyền đỉnh phong của Lam Mộng Đạo Tôn cũng sẽ không bị bức quá mức","bridge":true,"khoang":"@c1584"}],"tuViMoc":[{"chuong":"@c1582","canhGioi":"Không Huyền đỉnh phong","text":"Tự tiết lộ tu vi Không Huyền đỉnh phong, sớm có thể bước vào huyền kiếp độ kiếp, nếu vượt chín lần thì đạt Không Kiếp. Nếu không vì đạo tâm bất viên mãn thì thậm chí Chưởng Tôn cũng không địch nổi.","importance":"major"}],"nhanMach":[{"ten":"Lý Thiến Mai","tag":"cha-me","quanHe":"Con gái","ghiChu":"Dẫn tới trước Vương Lâm @c1581"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đề nghị làm con rể, sẵn sàng liên minh","ghiChu":"@c1581"},{"ten":"Diệu Âm đạo tôn","tag":"doi-thu","quanHe":"Kẻ địch, bị Lam Mộng chặn lại khi lao tới tấn công Vương Lâm"},{"ten":"Cửu Thiên ma tôn","tag":"doi-thu","quanHe":"Kẻ địch, bị Lam Mộng chặn lại cùng Diệu Âm và Đại Hoang"},{"ten":"Đại Hoang Thượng Nhân","tag":"doi-thu","quanHe":"Kẻ địch, bị Lam Mộng chặn lại cùng hai người kia"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Con rể (Lý Thiến Mai chọn Vương Lâm)","ghiChu":""},{"ten":"Chưởng Tôn","tag":"doi-thu","quanHe":"Mối đe dọa duy nhất trên đường","ghiChu":"Có thể dẫn động huyền kiếp buộc Chưởng Tôn phải tránh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1581","@c1582","@c1583","@c1584"]},{"id":"chu-vu-thai","name":"Chu Vũ Thái","tabs":{"kinhLich":[]},"nguon":["@c1581"]},{"id":"kien-phong","name":"Kiền Phong","tabs":{"kinhLich":[]},"nguon":["@c1581"]},{"id":"thanh-thuy","name":"Thanh Thủy","tabs":{"kinhLich":[{"mucCt":"vua","text":"Được Vương Lâm kể cho Hồng Điệp nghe: khổ mệnh, toàn tộc bị diệt, thê tử chết, chỉ còn nữ nhi duy nhất đã luân hồi, trên vai trái có thai ký màu hồng không bao giờ tiêu tán. Hồng Điệp nghe xong lảo đảo tái nhợt, lao về La Thiên muốn gặp Thanh Thủy.","anchor":"Sư huynh chỉ là một người khổ mệnh.hắn thủa nhỏ toàn tộc bị diệt vong","bridge":true,"khoang":"@c1582"},{"mucCt":"vua","text":"Phẫn nộ vì tiên giới bị xâm nhập, ngưng tụ sát lục bổn nguyên ngoài thân. Không bị lực lượng huyết mạch tiên nhân ảnh hưởng, lao xuyên lốc vàng tiến vào tiên giới phản kích.","anchor":"Chỉ có Thanh Thủy là không chịu chút ảnh hưởng bởi lực lượng huyết mạch này","bridge":true,"khoang":"@c1593"},{"importance":"major","mucCt":"vua","chuong":"@c1600","tieuDe":"Bị nhận ra là thất phách Thất Thải Thiên Tôn","text":"Bị Vương Lâm nhận ra chính là một trong thất phách của Thất Thải Thiên Tôn, giải thích cuộc đời thê thảm, đạt sát lục bổn nguyên, vừa vào bước thứ ba đã cực mạnh. Đây là suy luận của Vương Lâm dựa trên bí mật ba hồn bảy phách vừa được tiết lộ.","anchor":"Thanh Thuỷ sư huynh chính là một trong thất phách của Thất Thải Thiên Tôn"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1582","@c1592","@c1593","@c1600"]},{"id":"dieu-am-dao-ton","name":"Diệu Âm đạo tôn","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Thái Cổ Ngũ Tôn","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Một trong Thái Cổ Ngũ Tôn, vốn bị Vương Lâm nhốt trong vùng đất cổ mộ, sau được Chưởng Tôn giải cứu.","vaiTro":"Đối thủ của Vương Lâm, thành viên Thái Cổ Ngũ Tôn","tinhCach":"Hiếu chiến; mang oán khí sâu nặng với Vương Lâm","tabs":{"diem":[{"text":"Từng bị Vương Lâm nhốt trong vùng đất cổ mộ, mang sát khí và oán hận.","chuong":"@c1582"}],"kinhLich":[{"mucCt":"vua","text":"Vốn bị Vương Lâm nhốt trong cổ mộ, được Chưởng Tôn cứu ra. Cùng Cửu Thiên ma tôn và Đại Hoang Thượng Nhân mang sát khí lao tới tấn công Vương Lâm nhưng bị Lam Mộng Đạo Tôn chủ động chặn lại.","anchor":"Diệu Âm, Cửu Thiên, Đại Hoang, ba ngươi biến cho lão phu","bridge":true,"khoang":"@c1582"},{"text":"Cùng Cửu Thiên và Đại Hoang Thượng Nhân hợp lực đánh Lam Mộng Đạo Tôn ba ngày, bại trận. Trọng thương, trăm năm không thể khôi phục đỉnh phong, tu vi rớt xuống Không Linh.","anchor":"Diệu âm đ*o tôn trọng thương trăm năm không thể khôi phục tu vi đỉnh phong, rớt xuống không linh","bridge":true,"khoang":"@c1583"},{"importance":"bridge","mucCt":"vua","chuong":"@c1594","tieuDe":"Gào thét lao tới giết Vương Lâm","text":"Thương thế chưa hồi phục nhưng vẫn gào thét lao tới chỗ Vương Lâm cùng Cửu Thiên ma tôn, cười nanh ác tự tin hắn không thể sống sót.","anchor":"Có những người này muốn giết ngươi thì ta không tin ngươi có thể sống nổi"},{"importance":"normal","mucCt":"vua","chuong":"@c1596","tieuDe":"Bị bắt gọn nguyên thần","text":"Xuất hiện cùng Cửu Thiên Ma Tôn và Thất Phi vây Vương Lâm. Bị mũi tên cung Lý Quảng đánh nổ tung thân thể, nguyên thần bị Vương Lâm vung tay áo bắt gọn.","anchor":"Diệu âm đ*o Tôn và Cửu Thiên Ma Tôn cũng phun máu tươi, thân thể nổ tung, huyết nhục mơ hồ, nguyên thần đang muốn lui lại thì bị tay áo Vương Lâm vung lên, trực tiếp bắt gọn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù, từng bị Vương Lâm nhốt trong cổ mộ"},{"ten":"Cửu Thiên ma tôn","tag":"dong-minh","quanHe":"Đồng minh, cùng tấn công Vương Lâm"},{"ten":"Đại Hoang Thượng Nhân","tag":"dong-minh","quanHe":"Đồng minh, cùng tấn công Vương Lâm"},{"ten":"Chưởng Tôn","tag":"dong-minh","quanHe":"Người giải cứu khỏi cổ mộ"},{"ten":"Lam Mộng Đạo Tôn","tag":"doi-thu","quanHe":"Bị Lam Mộng chặn lại khi tấn công Vương Lâm"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1582","@c1583","@c1594","@c1596"],"canhGioiCaoNhat":"Không Linh"},{"id":"cuu-thien-ma-ton","name":"Cửu Thiên ma tôn","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Thái Cổ Ngũ Tôn","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Một trong Thái Cổ Ngũ Tôn, vốn bị Vương Lâm nhốt trong cổ mộ, được Chưởng Tôn giải cứu.","vaiTro":"Đối thủ của Vương Lâm, thành viên Thái Cổ Ngũ Tôn","tinhCach":"Hung hãn; kiêng kỵ kẻ mạnh hơn","tabs":{"diem":[{"text":"Từng bị Vương Lâm nhốt trong cổ mộ, cùng Diệu Âm và Đại Hoang tấn công hắn.","chuong":"@c1582"}],"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1582","tieuDe":"Được giải cứu — bị Lam Mộng chặn","text":"Vốn bị Vương Lâm nhốt trong cổ mộ, được Chưởng Tôn cứu ra. Cùng Diệu Âm đạo tôn và Đại Hoang Thượng Nhân mang sát khí lao tới tấn công Vương Lâm nhưng bị Lam Mộng Đạo Tôn chặn lại, kiêng kỵ tu vi Không Huyền đỉnh phong của Lam Mộng.","anchor":"Cửu Thiên ma tôn và Đại Hoang Thượng Nhân cũng đưa mắt nhìn nhau, trong mắt đều hiện lên vẻ kiêng kỵ"},{"chuong":"@c1583","importance":"normal","tieuDe":"Bại trận mất hương hỏa giới tâm thần tổn thương","text":"Bại trận trước Lam Mộng Đạo Tôn, bị thương nhẹ hơn Diệu Âm Đạo Tôn nhưng hương hỏa giới đã bị hủy diệt, tâm thần thương tổn.","anchor":"Cửu Thiên bị thương nhẹ hơn Diệu âm đ*o tôn nhiều nhưng hương hỏa giới đã bị ta hủy diệt, bị thương tâm thần"},{"importance":"bridge","mucCt":"vua","chuong":"@c1594","tieuDe":"Muốn rút hồn Vương Lâm thiêu đốt vạn năm","text":"Thương thế chưa hồi phục nhưng vẫn lao tới chỗ Vương Lâm, muốn rút hồn hắn ra thiêu đốt vạn năm.","anchor":"Lão phu muốn rút hồn hắn ra, thiêu đốt vạn năm"},{"importance":"normal","mucCt":"vua","chuong":"@c1596","tieuDe":"Bị bắt gọn nguyên thần","text":"Xuất hiện cùng Diệu Âm Đạo Tôn và Thất Phi vây Vương Lâm. Bị mũi tên cung Lý Quảng đánh nổ tung thân thể, nguyên thần bị Vương Lâm bắt gọn.","anchor":"nguyên thần đang muốn lui lại thì bị tay áo Vương Lâm vung lên, trực tiếp bắt gọn"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù, từng bị Vương Lâm nhốt trong cổ mộ"},{"ten":"Diệu Âm đạo tôn","tag":"dong-minh","quanHe":"Đồng minh, cùng tấn công Vương Lâm"},{"ten":"Đại Hoang Thượng Nhân","tag":"dong-minh","quanHe":"Đồng minh, cùng tấn công Vương Lâm"},{"ten":"Chưởng Tôn","tag":"dong-minh","quanHe":"Người giải cứu khỏi cổ mộ"},{"ten":"Lam Mộng Đạo Tôn","tag":"doi-thu","quanHe":"Bị Lam Mộng chặn lại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1582","@c1583","@c1594","@c1596"]},{"id":"dai-hoang-thuong-nhan","name":"Đại Hoang Thượng Nhân","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Thái Cổ Ngũ Tôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Một trong Thái Cổ Ngũ Tôn, vốn bị Vương Lâm nhốt trong cổ mộ, được Chưởng Tôn giải cứu.","vaiTro":"Đối thủ của Vương Lâm, thành viên Thái Cổ Ngũ Tôn","tinhCach":"Mang oán hận; kiêng kỵ kẻ mạnh","tabs":{"diem":[{"text":"Từng bị Vương Lâm nhốt trong cổ mộ, cùng Diệu Âm và Cửu Thiên tấn công hắn.","chuong":"@c1582"}],"kinhLich":[{"mucCt":"vua","text":"Vốn bị Vương Lâm nhốt trong cổ mộ, được Chưởng Tôn cứu ra. Cùng Diệu Âm đạo tôn và Cửu Thiên ma tôn mang sát khí lao tới tấn công Vương Lâm nhưng bị Lam Mộng Đạo Tôn chặn lại.","anchor":"trong ba đạo cầu vồng đó chính là ba người mà Vương Lâm quen thuộc","bridge":true,"khoang":"@c1582"},{"text":"Bại trận nặng nhất trong ba người, dùng bí thuật bỏ chạy. Lam Mộng Đạo Tôn đoán hắn sống không quá mười năm.","anchor":"Đại Hoang Thượng Nhân bị thương nặng nhất, dùng bí thuật bỏ chạy. Hắn sống không quá mười năm nữa!","bridge":true,"khoang":"@c1583"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ thù, từng bị Vương Lâm nhốt trong cổ mộ"},{"ten":"Diệu Âm đạo tôn","tag":"dong-minh","quanHe":"Đồng minh, cùng tấn công Vương Lâm"},{"ten":"Cửu Thiên ma tôn","tag":"dong-minh","quanHe":"Đồng minh, cùng tấn công Vương Lâm"},{"ten":"Chưởng Tôn","tag":"dong-minh","quanHe":"Người giải cứu khỏi cổ mộ"},{"ten":"Lam Mộng Đạo Tôn","tag":"doi-thu","quanHe":"Bị Lam Mộng chặn lại"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1582","@c1583"]},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","mucCt":"gon","trangThai":"khong-ro","tabs":{"kinhLich":[{"chuong":"@c1583","importance":"normal","tieuDe":"Được Vương Lâm xác nhận là thê tử","text":"Được Vương Lâm tuyên bố vẫn là thê tử duy nhất, đợi nàng tỉnh dậy sẽ cùng thành thân.","anchor":"Uyển Nhi là thê tử của ta, đợi sau khi nàng tỉnh dậy chúng ta sẽ cùng nhau thành thân"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1583"]},{"id":"van-thu","name":"Văn Thú","cn":"纹兽","gioiTinh":"khong-ro","trangThai":"song","nguon":["@c1584","@c1585","@c1587"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1584","tieuDe":"Gặp lại Vương Lâm trong Phong Tiên giới","text":"Bị thất lạc trong đại chiến trăm năm trước, vào Phong Tiên giới sinh tồn, dẫn đàn Văn thú hung mãnh tàn sát các đàn khác trên khắp Phong Tiên giới để giải tỏa bi ai vì tìm không thấy chủ nhân. Khi cảm nhận được khí tức Vương Lâm, hàn quang trong mắt sụp đổ, kích động điên cuồng lao về phía chủ nhân.","anchor":"Nó run rẩy, hàn quang trong mắt sụp đổ, thay thế bằng vẻ mê man cả trăm năm nay không tiêu tan!"},{"importance":"normal","mucCt":"ky","chuong":"@c1585","tieuDe":"Tiến hóa gần bước thứ ba","text":"Dẫn đầu đàn trên vạn Văn thú, kích thước trăm trượng, tu vi tiếp cận bước thứ ba chỉ còn kém một bước lột xác. Hưng phấn hội ngộ Vương Lâm, lao tới đâm vào người hắn thể hiện tình cảm chủ thú. Dẫn Vương Lâm vào vùng sâu Phong Tiên giới, hút tinh hoa từ thi thể Văn thú ngàn trượng khiến toàn thân lóe kim quang. Dẫn Vương Lâm vào bên trong cái khe, nơi chứa hàng trăm vạn trứng Văn thú, hút sạch tinh hoa bên trong trứng — đây chính là nguồn cơ duyên giúp nó tiến hóa mạnh mẽ.","anchor":"Loại biến hóa này khiến cho Vương Lâm rất ngạc nhiên"},{"importance":"bridge","mucCt":"gon","chuong":"@c1587","text":"Đang thôn phệ trứng Văn thú trong thông đạo, sau khi Vương Lâm thu hết trứng thì hoan hỉ đi theo hắn rời đi.","anchor":"Văn vương hoan hỉ rít lên, lúc này không còn lưu luyến chút nào"}],"nhanMach":[],"tuViMoc":[]},"canhGioiCaoNhat":"Tiếp cận bước thứ ba (tương đương thiên nhân ngũ suy)","aliases":["Văn vương"]},{"id":"chuong-mon-phan-tong-quy-nhat","name":"Chưởng môn phân tông Quy Nhất tông","cn":"","aliases":["nam tử trung niên"],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không Huyền đỉnh phong","trangThai":"song","blurb":"Chưởng môn phân tông phía đông Quy Nhất tông trên Tiên Cương đại lục. Tu vi Không Huyền đỉnh phong, đã vượt qua nhiều lần huyền kiếp.","vaiTro":"Chưởng môn phân tông Quy Nhất tông, canh giữ Đông Đan chung","tinhCach":"Thận trọng; tôn trọng lời dặn sư huynh","tabs":{"diem":[{"text":"Tu vi Không Huyền đỉnh phong, đã vượt nhiều lần huyền kiếp, canh giữ Đông Đan chung theo lời dặn Mã sư huynh","chuong":"@c1586"},{"text":"Nhận ra mũi kiếm xuyên qua Đông Đan chung là kiếm của Diệp Mịch, quyết định không mở chuông theo lời dặn năm xưa của Mã sư huynh","chuong":"@c1586"},{"text":"Tu vi Không Huyền đỉnh phong, vượt nhiều lần huyền kiếp, nhận ra kiếm của Diệp Mịch ngay khi mũi kiếm lộ trên Đông Đan chung","chuong":"@c1586"}],"kinhLich":[{"chuong":"@c1586","importance":"normal","mucCt":"vua","tieuDe":"Mũi kiếm xuyên Đông Đan chung","text":"Khi Đông Đan chung chấn động, dẫn đầu bay tới, nhận ra mũi kiếm đỏ đậm tỏa huyết quang là kiếm của Diệp Mịch. Quyết định tạm không mở chuông theo lời dặn của Mã sư huynh năm đó, xác nhận lời đồn Diệp Mịch bị Thất Đạo Tông dẫn vào động phủ là thật.","anchor":"Kiếm của Diệp Mịch!"}],"tuViMoc":[{"chuong":"@c1586","canhGioi":"Không Huyền đỉnh phong","text":"Được giới thiệu với tu vi Không Huyền đỉnh phong, đã vượt qua nhiều lần huyền kiếp.","importance":"major"}],"nhanMach":[{"ten":"Mã sư huynh","tag":"su-mon","quanHe":"Sư huynh trong Quy Nhất tông, đã dặn dò trước khi dẫn người vào động phủ","ghiChu":"@c1586"},{"ten":"Diệp Mịch","tag":"khac","quanHe":"Nhận diện qua huyết kiếm","ghiChu":"Biết Diệp Mịch bị dẫn vào động phủ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1586"]},{"id":"ma-su-huynh","name":"Mã sư huynh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Sư huynh trong Quy Nhất tông, từng dùng chí bảo tông phái mở thông đạo tới động phủ Thất Đạo Tông, dẫn người đi vào và dặn chuông không được mở.","vaiTro":"Thành viên Quy Nhất tông, người mở thông đạo tới động phủ","tinhCach":"Kiên quyết; có mưu lược","tabs":{"diem":[{"text":"Dùng chí bảo Quy Nhất tông mở thông đạo tới động phủ Thất Đạo Tông, dặn chuông không được mở, phải tự mình trở về","chuong":"@c1586"}],"kinhLich":[{"chuong":"@c1586","importance":"normal","mucCt":"gon","tieuDe":"Mở thông đạo vào động phủ","text":"Nghiên cứu rất lâu rồi dùng chí bảo Quy Nhất tông mở thông đạo tới động phủ Thất Đạo Tông, dặn chuông không được mở, dẫn người đi vào, phải tự mình trở về.","anchor":"Mã sư huynh trước khi dẫn người đi đã từng nói, chuông này không thể mở ra, hắn phải tự mình trở về"}],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng môn phân tông Quy Nhất tông","tag":"su-mon","quanHe":"Sư đệ, chưởng môn phân tông","ghiChu":"@c1586"},{"ten":"Chưởng môn phân tông Quy Nhất","tag":"su-mon","quanHe":"Sư đệ trong Quy Nhất tông, người nhớ lời dặn của Mã sư huynh","ghiChu":"@c1586"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1586"],"canhGioiCaoNhat":"khong-ro"},{"id":"dao-nhan-bay-mau","name":"Đạo nhân bảy màu","cn":"","aliases":["Thất Thải Tiên Tôn","Quái nhân tóc bạc","Thất Thải Thiên Tôn"],"gioiTinh":"nam","trangThai":"song","tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1589","tieuDe":"Tiết lộ huyết trận hoàn thành, tìm người thứ ba","text":"Xuất hiện trong hắc động do mấy tu chân tinh tạo thành dòng xoáy, tiết lộ chính hắn đã sắp đặt cho Chưởng Tôn đưa cung Lý Quảng cho Vương Lâm coi đó là cơ duyên. Nhận xét Vương Lâm rất giống chiến lão quỷ, muốn lợi dụng nếu Vương Lâm không phải người thứ ba. Huyết trận đã hoàn thành, đang tiếp tục tính toán vị trí người thứ ba đã luân hồi vô số lần.","anchor":"Huyết trận đã thành, đang tiếp tục tính toán, không bao lâu nữa ta sẽ biết được người thứ ba luân hồi vô số lần rốt cục ở đâu"},{"chuong":"@c1597","importance":"normal","mucCt":"ky","tieuDe":"Lộ diện tinh không, tuyên bố thu hồi cung Lý Quảng","text":"Hiện thân từ ánh sáng bảy màu dưới hình nam tử trung niên mặc đạo bào tiên phong đạo cốt. Điểm một chỉ ngưng tụ ánh sáng bảy màu vạn trượng nhắm Vương Lâm nhưng bị ngọc thủ Phàn San Lộ thi triển Thái Ngọc Thất Thủ Ấn chặn lại. Bình thản hóa giải ấn quyết, nhận ra thần thông mình đạt được không phải toàn bộ. Tuyên bố cung Lý Quảng đã hoàn thành sứ mạng cần thu hồi, rồi biến mất bước vào tinh không đuổi theo.","anchor":"Cây cung của Lý Quảng cũng đã hoàn thành sứ mạng rồi, nên thu hồi thôi"},{"chuong":"@c1598","importance":"normal","mucCt":"ky","tieuDe":"Truy sát Vương Lâm đòi cung Lý Quảng","text":"Xuất hiện trong ánh sáng bảy màu, truy sát Vương Lâm đòi cung tên Lý Quảng. Hừ lạnh tiêu diệt hơn trăm mãnh thú, sóng âm từ lời nói khiến Vương Lâm phun máu. Gọi Phàn San Lộ là đệ nhất phi. Triệu chín hỏa điểu (chín tu chân tinh luyện hóa) tấn công. Phóng tinh thể bảy màu vây khốn hai người nhưng bị phá vỡ bởi ấn quyết và viện trợ từ tỷ tỷ Phàn San Lộ. Tự xưng là Thất Thải Tiên Tôn.","anchor":"Lão phu đương nhiên là Thất Thải Tiên Tôn. Ta vốn không muốn giết ngươi, chỉ cần thu hồi cung tên"},{"importance":"normal","mucCt":"vua","chuong":"@c1599","tieuDe":"Tấn công chiến thuyền, bị lộ quá khứ ám toán Phàn San Mộng","text":"Bước ra từ tinh không, nhìn chiến thuyền thấy quen nhưng không nhớ do chưa đạt ký ức đầy đủ. Ra tay phá vỡ một tầng phòng hộ, đẩy thuyền lùi mười trượng. Theo lời Phàn San Mộng tiết lộ: năm xưa nhờ cơ duyên lấy mảnh vỡ từ Thái Cổ Thần Cảnh, ám toán Phàn San Mộng chiếm tu vi để mở mảnh vỡ, dụ Đạo Cổ Diệp Mịch tới phong kín tông sơn rồi nhờ Lý Quảng chém giết Đạo Cổ.","anchor":"Ta còn chưa đạt được ký ức, rất nhiều chuyện không nhớ ra"},{"importance":"normal","mucCt":"ky","chuong":"@c1600","tieuDe":"Được xác nhận là hồn thứ nhất Thất Thải Thiên Tôn","text":"Được nữ tử tiết lộ chính là hồn thứ nhất của Thất Thải Thiên Tôn, nắm toàn bộ đạo thuật thần thông cả đời, chiến lực cao nhất trong ba hồn. Chiếm cứ giới ngoại, ép tiên phi nghe lệnh, thu phục Chưởng Tôn. Không ngừng tìm kiếm hồn thứ ba để dung hợp trở thành Thất Thải Thiên Tôn hoàn chỉnh.","anchor":"Một trong tam hồn có được thần thông chính là đạo nhân bảy màu"},{"chuong":"@c1603","importance":"normal","mucCt":"vua","tieuDe":"Lên thuyền phá tầng hai, bị tuyên bố là huyễn ảnh","text":"Đặt chân lên boong tàu tầng một khi Phàn San Mộng mở phòng hộ, xuyên qua vào tầng hai và phá dần cấm chế trong hai canh giờ khiến tầng này sụp đổ. Vương Lâm tuyên bố sự hiện diện của hắn trên thuyền là giả — phần của huyễn giới do Phàn San Lộ tạo ra, còn bản thể có lẽ là thật.","anchor":"Đạo nhân bảy màu có lẽ là thật nhưng hắn ở trên thuyền này là giả"},{"chuong":"@c1605","importance":"normal","mucCt":"ky","tieuDe":"Chìm đắm trong ảo giác, Vương Lâm thử xâm nhập thất bại","text":"Bị Vương Lâm phát hiện đang ngồi khoanh chân trên thi hài mãnh thú, toàn thân tỏa ánh sáng bảy màu, thần sắc biến đổi phức tạp — chìm đắm trong ảo giác không thể tự kiềm chế. Xung quanh có cấm chế tự động hủy diệt vô thanh vô tức mọi vật trong phạm vi trăm trượng. Vương Lâm thi triển Mộng Đạo thuật cố xâm nhập ảo giác nhưng thất bại do tu vi quá cao và cấm chế ngăn cản.","anchor":"Toàn thân kẻ đó tỏa ra ánh sáng bảy màu, ngồi yên bất động"},{"importance":"normal","mucCt":"ky","chuong":"@c1608","tieuDe":"Mất dấu hồn thứ ba, thề giết Vương Lâm","text":"Trong huyễn cảnh tầng hai, lần đầu tiên tới gần được hồn thứ ba, nhìn thấy hồn thứ ba xuyên qua Triệu Hà hướng Côn Hư vạn năm sau, cực kỳ kích động. Bị tiếng rống Vương Lâm phá tan huyễn cảnh, tinh đồ sụp đổ, hồn thứ ba tiêu tán ngay trước mắt. Phẫn nộ tột cùng gào thét, thề không làm người nếu không giết Vương Lâm, mang sát khí truy kích.","anchor":"Vương Lâm, thất thải ta nếu không giết ngươi, thề không làm người!"}],"tuViMoc":[],"nhanMach":[{"ten":"Phàn San Lộ","tag":"doi-thu","quanHe":"Kẻ thù (đệ nhất phi bị hắn gây thương)","ghiChu":"Muội muội đạo lữ, bị hắn phản bội gây thương tích"},{"ten":"Phàn San Mộng","tag":"the-thiep","quanHe":"Đạo lữ (bạn đời)","ghiChu":"Bị hắn dùng làm mồi đoạt bảo vật liên quan vầng mặt trời thứ chín"},{"ten":"Phàn San Lộ","tag":"khac","quanHe":"Tiểu di (muội muội đạo lữ)","ghiChu":"Nhận ra qua Thái Ngọc Thất Thủ Ấn, từng gây thương tích cho nàng"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1586","@c1589","@c1597","@c1598","@c1599","@c1600","@c1603","@c1605","@c1608"],"tinhCach":[]},{"id":"chien-lao-quy","name":"Chiến lão quỷ","aliases":["Chiến Không Liệt"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"vua","chuong":"@c1588","tieuDe":"Ẩn thế trong Lôi Tiên Giới quan sát Vương Lâm","text":"Ẩn thế sâu trong Lôi Tiên Giới, thần thức Vương Lâm không phát hiện ra nhưng hắn lại quan sát được Vương Lâm. Tự hỏi Vương Lâm biết được bao nhiêu và có phải là người thứ ba hay không, không ngăn cản Vương Lâm rời đi.","anchor":"hắn rốt cục biết được bao nhiêu rồi.hắn rốt cục có phải là người thứ ba hay không"}],"tuiDo":{}},"nguon":["@c1588"]},{"id":"thanh-lam","name":"Thanh Lâm","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1588","tieuDe":"Dẫn đầu thu tinh hồn và vái tiễn Vương Lâm","text":"Dẫn đầu mấy vạn tu sĩ giới nội tản ra tứ đại tinh vực thu tinh hồn theo truyền âm của Vương Lâm, cuối cùng vái tiễn Vương Lâm rời đi.","anchor":"Dưới sự dẫn đầu của Thanh Lâm bọn họ liền nhận được truyền âm của Vương Lâm"},{"chuong":"@c1592","importance":"normal","tieuDe":"Bái kiến tiên nhân viễn cổ bị phớt lờ","text":"Sắc mặt tái nhợt khi cảm nhận khí tức viễn cổ tiên vực, bay lên tinh không cùng Hồng Sam Tử, Nam Vân Tử, Thanh Thủy. Xưng là đệ tử Phong Tôn, cung kính bái kiến tiên nhân viễn cổ nhưng bị hoàn toàn phớt lờ — tiên nhân cười lớn xuyên qua bốn người lao thẳng về tân tiên giới thôn phệ hương hỏa. Trái tim chấn động trước cảnh tượng này.","anchor":"Đệ tử của Phong Tôn, Thanh Lâm, bái kiến các vị tiên nhân viễn cổ","mucCt":"ky"},{"importance":"bridge","mucCt":"gon","chuong":"@c1593","text":"Nổi giận gầm lên yêu cầu tiên nhân dừng tay nhưng bị lốc vàng huyết mạch trấn áp phải lui lại.","anchor":"Thanh Lâm nổi giận gầm lên một tiếng, trực tiếp đạp bước mà đi"}],"tuiDo":{}},"nguon":["@c1588","@c1592","@c1593"]},{"id":"tu-do-nam","name":"Tư Đồ Nam","aliases":["Tham Lang"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1588","tieuDe":"Được Vương Lâm gửi gắm bố cáo hậu thế","text":"Được Vương Lâm gửi gắm: nếu Vương Lâm chết, bố cáo toàn thiên hạ chuyện Vương Lâm đã nói, viết thành ngọc giản lưu trên mỗi tu chân tinh và trong tân tiên giới. Vái tiễn Vương Lâm cùng mấy vạn tu sĩ.","anchor":"Tư Đồ, nếu ta chết đi, mong ngươi nói chuyện ta đã nói cho ngươi bố cáo toàn thiên hạ"},{"chuong":"@c1592","importance":"normal","tieuDe":"Không kính sợ viễn cổ tiên vực","text":"Ở trong đám tu sĩ trên mặt đất tân tiên giới, nhìn khe viễn cổ tiên vực nhớ lại lời Vương Lâm từng nói, không có chút kính sợ, chỉ cảm thấy mờ mịt và phức tạp. Chưa tiết lộ nội dung ấy cho ai.","anchor":"Lúc này nhìn thấy cái khe viễn cổ tiên vực, trong lòng hắn không có chút kính sợ, chỉ cảm thấy mờ mịt và phức tạp","mucCt":"vua"},{"importance":"normal","mucCt":"vua","chuong":"@c1593","tieuDe":"Bóp nát ngọc giản kích hoạt thân ảnh Vương Lâm","text":"Giật mình tỉnh lại, bóp nát ngọc giản mà Vương Lâm giao ba năm trước ở Chu Tước Tinh. Thần thức Vương Lâm tuôn ra huyễn hóa thành thân ảnh, phát sát lục đuổi tiên nhân khỏi tiên giới.","anchor":"Ngọc giản này là ba năm trước khi hắn gặp Vương Lâm ở Chu Tước Tinh"},{"importance":"normal","mucCt":"ky","chuong":"@c1608","tieuDe":"Tái hiện trong đào viên, bị giam trăm năm","text":"Xuất hiện từ khe nứt gần tế đàn, trong không gian kỳ dị dạng đào viên. Khuôn mặt tiều tụy, mắt vô thần, bị hai cô bé Hàm Hàm và Oa Oa giữ suốt một trăm năm bắt kể chuyện cổ. Ban đầu khi mới tới từng uy hiếp hai cô bé nhưng bị khuất phục. Cầu xin được tha, khóc lóc nói không còn chuyện cổ, muốn uống nước. Đã kể chuyện tới đoạn về Vọng Nguyệt.","anchor":"Các tiểu tổ tông ơi, các người buông tha cho ta đi"}],"tuiDo":{},"nhanMach":[{"ten":"Hàm Hàm","tag":"khac","quanHe":"Cô bé giam giữ Tham Lang trong đào viên","ghiChu":"Bắt kể chuyện cổ suốt trăm năm @c1608"},{"ten":"Oa Oa (đào viên)","tag":"khac","quanHe":"Cô bé giam giữ Tham Lang trong đào viên","ghiChu":"Đề nghị kể thêm ngàn năm mới thả @c1608"}],"tuViMoc":[]},"nguon":["@c1588","@c1592","@c1593","@c1608"],"trangThai":"song"},{"id":"hong-sam-tu","name":"Hồng Sam Tử","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1588","text":"Có mặt trong đám mấy vạn tu sĩ vái tiễn Vương Lâm rời đi nghịch tiên.","anchor":"kể cả Thanh Lâm, Hồng Sam Tử, Tư Đồ Nam đều hướng về phía Vương Lâm vái một vái"},{"importance":"bridge","mucCt":"gon","chuong":"@c1593","text":"Cùng Nam Vân Tử bước ra đối mặt tiên nhân nhưng bị lốc vàng huyết mạch trấn áp phải lui lại.","anchor":"Hồng Sam Tử, Nam Vân Tử sửng sốt một chút, lập tức thần sắc đại biến"}],"tuiDo":{}},"nguon":["@c1588","@c1593"]},{"id":"tam-phi","name":"Tam phi","gioiTinh":"nu","aliases":[],"theLuc":[{"ten":"Bát phi tiên tôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong bát phi của tiên tôn, nữ tử bạch y dung nhan tuyệt mỹ, tính tình băng lạnh. Sau khi rời vùng đất cổ mộ đã ở trong Thái Cổ Tinh Thần chờ đợi điều gì đó.","vaiTro":"Một trong bát phi tiên tôn, chờ đợi bí ẩn trong Thái Cổ Tinh Thần","tinhCach":"Băng lạnh; bí ẩn; kiên nhẫn chờ đợi","nguon":["@c1589","@c1593"],"tabs":{"diem":[{"text":"Một trong bát phi tiên tôn, dung nhan tuyệt mỹ, băng lạnh","chuong":"@c1589"},{"text":"Rời vùng đất cổ mộ rồi ở Thái Cổ Tinh Thần chờ đợi mục đích chưa rõ","chuong":"@c1589"}],"kinhLich":[{"mucCt":"vua","text":"Nữ tử bạch y dung nhan tuyệt mỹ, băng lạnh, đang khoanh chân trên đỉnh núi một tu chân tinh trong Thái Cổ Tinh Thần. Sau khi từ vùng đất cổ mộ đi ra đã ở đây chờ đợi, mở mắt nhận ra Vương Lâm xuất hiện và nghi hoặc hắn muốn làm gì.","anchor":"Nữ tử này chính là một trong bát phi của tiên tôn, tam phi","bridge":true,"khoang":"@c1589"},{"importance":"bridge","mucCt":"gon","chuong":"@c1593","text":"Tâm thần chấn động khi thấy Vương Lâm hành động, vội vàng vọt tới.","anchor":"Dù là tiên phi thứ ba thì tâm thần cũng chấn động, vội vàng vọt tới"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Nhận ra sự xuất hiện của Vương Lâm, nghi hoặc mục đích"}],"tuiDo":{}}},{"id":"thien-van-tu","name":"Thiên Vận Tử","nguon":["@c1589","@c1601","@c1608"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c1589","tieuDe":"Cảm ứng biến đổi kinh thiên sắp xảy ra","text":"Vẫn ngồi khoanh chân trên khối đá ở Triệu Hà tinh vực, bàn tay không ngừng biến hóa tính toán, ánh mắt ngày càng sáng. Là người duy nhất ngoài Vương Lâm hơi cảm ứng được biến đổi kinh thiên chỉ còn mười hai giờ nữa sẽ xảy ra.","anchor":"Ánh mắt Thiên Vận Tử lộ ra ánh sáng kỳ dị, bàn tay không ngừng biến hóa nhanh"},{"chuong":"@c1601","importance":"bridge","mucCt":"gon","text":"Được Vương Lâm nhắc đến trong nội tâm như người duy nhất mà hắn không thể nắm được tâm tư.","anchor":"trừ Thiên Vận Tử là hắn không thể nắm được"},{"importance":"bridge","mucCt":"gon","chuong":"@c1608","tieuDe":"","text":"Hồn phách bị Vương Lâm dung nhập để triển khai bói toán xác nhận tế đàn là sinh cơ.","anchor":"dung nhập bên trong hồn phách của Thiên Vận Tử, triển khai bói toán"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"trangThai":"song","cn":"天运子","gioiTinh":"nam"},{"id":"that-phi","name":"Thất phi","aliases":["tiên phi thứ bảy","Viễn cổ Thất Phi"],"nguon":["@c1589","@c1594","@c1596","@c1597"],"tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1589","text":"Đang ẩn tu trong khe khổng lồ ở Thái Cổ Tinh Thần, mở mắt lộ ánh sáng kỳ dị khi cảm nhận Vương Lâm xuất hiện.","anchor":"giờ phút này thất phi mở hai mắt, lộ ra ánh sáng kỳ dị"},{"importance":"bridge","mucCt":"vua","chuong":"@c1594","tieuDe":"Oán hận lao tới giết Vương Lâm","text":"Sắc mặt tái nhợt, oán hận ngập trời, muốn tự tay giết Vương Lâm, cùng Diệu Âm đạo tôn và Cửu Thiên ma tôn đồng loạt hướng về phía hắn.","anchor":"Vương Lâm, ta muốn tự tay giết ngươi"},{"mucCt":"vua","text":"Xuất hiện cùng Diệu Âm Đạo Tôn và Cửu Thiên Ma Tôn vây Vương Lâm, khi thấy cung Lý Quảng hiện ra liền sững lại. Bị mũi tên trọng thương phun máu tươi nhưng nhờ là tiên phi có chí bảo phòng thân nên may mắn trốn thoát.","anchor":"chỉ có thất phi là sau khi lui lại liền phun một ngụm máu tươi, bị trọng thương dưới một tiễn vừa rồi, nhưng vì là tiên phi, có chí bảo phòng thân nên mới may mắn trốn thoát","bridge":true,"khoang":"@c1596"}],"tuViMoc":[],"nhanMach":[{"ten":"Phàn San Lộ","tag":"ho-hang","quanHe":"Đại tỷ (đệ nhất phi)","ghiChu":"Cùng là thất phi Thất Đạo Tông, thất phi gọi nàng là đại tỷ"}],"tuiDo":{}}},{"id":"viem-long","name":"Viêm long","aliases":["Tiểu Hồng","huyết viêm long","rồng ngốc"],"tabs":{"kinhLich":[{"importance":"major","mucCt":"ky","chuong":"@c1590","tieuDe":"Tái xuất và bị Vương Lâm chặn đường","text":"Sau trăm năm kể từ vùng đất Điên Lạc, đã tự lập Tiên Long Đạo với hơn ngàn tu sĩ, sống hưởng thụ trên đài linh thạch ngàn trượng trong thế giới động phủ. Khi đoàn Tiên Long Đạo tiến gần khu vực Vương Lâm, bị thần thức các toàn năng Thái Cổ Tinh Thần áp chế, hoảng sợ gần vỡ mật, tự hạ mình xưng chỉ là một con rắn. Bỏ đài linh thạch định tẩu nhưng bị Vương Lâm chặn đường, ngốc nghếch phun hỏa cầu tấn công nhưng bị phá tan dễ dàng, cuối cùng run rẩy choáng váng nhận ra thực lực khủng khiếp của đối phương.","anchor":"con rồng ngốc nghếch này gào lên một tiếng nức nở"},{"importance":"normal","mucCt":"ky","chuong":"@c1591","tieuDe":"Bị Vương Lâm thu phục, lộ lai lịch Liên Đạo Phi","text":"Thi triển toàn lực bao phủ ngọn lửa tháo chạy nhưng cảm nhận hỏa bổn nguyên của Vương Lâm mạnh hơn rất nhiều. Bị ấn quyết Chu Tước kích hoạt ấn ký trên mi tâm, đau đớn kêu thảm rồi đầu hàng. Hiện nguyên hình vạn trượng nhìn về Tiên Long Tông mà khóc. Xin Vương Lâm phối hợp diễn kịch giữ thể diện, tuyên bố Vương Lâm làm phó tông chủ trước hơn ngàn môn đồ rồi sai họ lui về. Khai nhận tên Tiểu Hồng do chủ nhân cũ đặt, xác nhận đến từ Tiên Cương đại lục, theo Liên Đạo Phi cùng một kẻ khác vào Thái Cổ Tinh Thần, bị lừa tới Thất Đạo Tông rồi bị bắt. Xác nhận Liên Đạo Phi đã chết. Bị Vương Lâm thu vào khe trữ vật.","anchor":"Chủ nhân bảo ta gọi là Tiểu Hồng rất hay, thế nên mới đặt ta là Tiểu Hồng!"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân mới, dùng ấn quyết Chu Tước thu phục","ghiChu":"@c1591"},{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"Chủ nhân cũ, đã chết","ghiChu":"Theo Liên Đạo Phi từ Tiên Cương đại lục vào Thái Cổ Tinh Thần @c1591"}],"tuViMoc":[],"diem":[{"text":"Tự xưng tiên long nhưng thực lực chỉ tương đương Không Niết sơ kỳ, bị Vương Lâm dùng ấn quyết Chu Tước trấn áp dễ dàng.","chuong":"@c1591"},{"text":"Linh trí cực cao, nói tiếng người lưu loát, xin chủ nhân mới diễn kịch giữ thể diện trước đám môn đồ.","chuong":"@c1591"},{"text":"Chủ nhân cũ là Liên Đạo Phi, trong thân ẩn chứa huyết mạch tiên nhân.","chuong":"@c1591"}]},"nguon":["@c1590","@c1591"],"canhGioiCaoNhat":"Không Niết sơ kỳ (tương đương)","trangThai":"song","vaiTro":"Linh thú của Liên Đạo Phi, sau bị Vương Lâm thu phục, tự xưng tiên long lập Tiên Long Tông","tinhCach":"Háo danh, sợ mạnh, khóc nhè, linh trí cao, trung thành với chủ","blurb":"Huyết viêm long tự xưng tiên long, lập Tiên Long Tông nô dịch hơn ngàn tu sĩ trong Thái Cổ Tinh Thần. Thực chất là thú cưỡi cũ của Liên Đạo Phi, trong thân ẩn chứa huyết mạch tiên nhân.","cn":"炎龙","gioiTinh":"khong-ro","theLuc":[{"ten":"Tiên Long Đạo","trangThai":"gan-bo"}]},{"id":"lien-dao-phi","name":"Liên Đạo Phi","cn":"连道飞","aliases":["người điên"],"gioiTinh":"nam","trangThai":"song","blurb":"Chủ nhân cũ của viêm long Tiểu Hồng, tự xưng bổn vương. Từ Tiên Cương đại lục vào Thái Cổ Tinh Thần cùng một kẻ khác, bị lừa tới Thất Đạo Tông rồi bị bắt. Viêm long xác nhận đã chết.","vaiTro":"Chủ nhân cũ của viêm long Tiểu Hồng, nhân vật bí ẩn tự xưng bổn vương","tinhCach":"Điên cuồng, bí ẩn","theLuc":[],"tabs":{"diem":[{"text":"Tự xưng bổn vương, nhiều lần gọi tên Tiểu Hồng khi còn sống, nói thứ đồ của bổn vương ở chỗ Tiểu Hồng.","chuong":"@c1591"},{"text":"Từ Tiên Cương đại lục vào Thái Cổ Tinh Thần, bị lừa tới Thất Đạo Tông rồi bị bắt, cuối cùng chết.","chuong":"@c1591"}],"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1591","tieuDe":"Viêm long xác nhận đã chết","text":"Viêm long Tiểu Hồng xác nhận Liên Đạo Phi chính là chủ nhân cũ của nó, đã chết. Vương Lâm nhớ lại lời người điên năm xưa nhiều lần gọi Tiểu Hồng và nói thứ đồ của bổn vương ở chỗ Tiểu Hồng.","anchor":"Liên Đạo Phi là chủ nhân trước kia của ta.đáng tiếc là hắn đã chết rồi."},{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Bị Phàn San Mộng dụ tới Thất Đạo Tông","text":"Được Phàn San Mộng nhắc: vốn mê sắc đẹp nàng, bị nàng dụ tới Thất Đạo Tông để phá cuộc.","anchor":"Ta đem tin tức này nói cho Liên Đạo Phi vốn vẫn không buông tha sắc đẹp của ta"},{"importance":"normal","mucCt":"ky","chuong":"@c1600","tieuDe":"Bị thiên đạo nuốt — nhờ bất diệt thể vẫn sống","text":"Được kể lại: tu vi thông thiên, một mình đánh tứ đại chiến tướng và đệ tử Thất Đạo Tông. Cuối cùng bị Thất Thải Thiên Tôn triệu hồi thiên đạo nuốt, trọng thương. Nhờ tiên nhân bất diệt thể không chết, vẫn ở đâu đó trong thế giới động phủ.","anchor":"lấy tiên nhân bất diệt thể của hắn thì sẽ không thể chết được"},{"importance":"normal","mucCt":"ky","chuong":"@c1606","tieuDe":"Lộ diện trong ký ức — phá sơn môn Tiên Tôn","text":"Trong ký ức Thất Thải Tiên Tôn xuất hiện dưới hình dạng nam tử trung niên áo xám, tướng mạo anh tuấn, hai mắt hàn quang, kiêu hãnh tới cực điểm. Cười điên cuồng phá hủy lầu các sơn môn Tiên Tôn, phía sau có viêm long đỏ rực bay múa và thiếu niên đầu trọc áo vải xanh đang chém giết với Thanh Long chiến tướng. Xưng bổn vương, thừa nhận bị Phàn San Mộng câu dẫn, nói chỉ vì mảnh vỡ mà Tiên Tôn đạt được. Khi Tiên Tôn triệu hồi Thiên Đạo đồng quy vu tận, biến sắc thốt lên Thiên Đạo.","anchor":"Là nàng câu dẫn bổn vương, nhưng bổn vương đối với đạo lữ của người khác không có hứng thú"}],"tuViMoc":[],"nhanMach":[{"ten":"Viêm long","tag":"khac","quanHe":"Thú cưỡi / linh thú trung thành","ghiChu":"@c1591"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người từng gặp khi còn sống (người điên)","ghiChu":"@c1591"},{"ten":"Thất Thải Tiên Tôn","tag":"doi-thu","quanHe":"Mục tiêu tấn công","ghiChu":"Phá sơn môn để đoạt mảnh vỡ, bị Phàn San Mộng câu dẫn"},{"ten":"Phàn San Mộng","tag":"khac","quanHe":"Người câu dẫn","ghiChu":"Nàng câu dẫn Liên Đạo Phi tới tấn công Tiên Tôn"}],"tuiDo":{}},"nguon":["@c1591","@c1599","@c1600","@c1606"]},{"id":"chien-khong-liet","name":"Chiến Không Liệt","aliases":["chiến lão quỷ"],"nguon":["@c1592","@c1600"],"tabs":{"kinhLich":[{"chuong":"@c1592","importance":"normal","tieuDe":"Cảnh giác trước khe nứt viễn cổ tiên vực","text":"Đang ngồi trong Lôi Tiên giới, nghe tiếng chấn động liền đứng phắt dậy, vọt ra Thiểm Lôi tộc, nhìn chằm chằm khe nứt tinh không, hai mắt lộ hàn quang, nhận ra đây là viễn cổ tiên vực.","anchor":"Đôi mắt hắn lộ ra ánh sáng kỳ dị, nhìn chằm chằm vào cái khe vừa bị xé mở trong tinh không","mucCt":"vua"},{"importance":"major","mucCt":"ky","chuong":"@c1600","tieuDe":"Bị suy luận là hồn thứ hai Thất Thải Thiên Tôn","text":"Bị Vương Lâm suy luận chính là hồn thứ hai của Thất Thải Thiên Tôn — hồn chứa ý cảnh và bổn nguyên lực, giải thích vì sao đủ tư cách đối kháng đạo nhân bảy màu và vì sao Chưởng Tôn e sợ khi gặp lại. Đây là suy luận của Vương Lâm, chưa được xác nhận tuyệt đối.","anchor":"chẳng lẽ Chiến lão quỷ này chính là hồn thứ hai"}],"nhanMach":[],"tuViMoc":[]}},{"id":"phong-ton","name":"Phong Tôn","gioiTinh":"nam","theLuc":[{"ten":"Viễn Cổ Tiên Vực","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Tiên nhân viễn cổ mà Thanh Lâm xưng là đệ tử, được nhắc tên khi Thanh Lâm bái kiến đám tiên nhân bước ra từ khe nứt viễn cổ tiên vực.","vaiTro":"Sư tôn của Thanh Lâm, tiên nhân viễn cổ","tinhCach":"Chưa rõ","tabs":{"diem":[{"text":"Thanh Lâm xưng là đệ tử của Phong Tôn khi bái kiến tiên nhân viễn cổ","chuong":"@c1592"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Thanh Lâm","tag":"su-mon","quanHe":"Đệ tử"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1592"]},{"id":"nam-van-tu","name":"Nam Vân Tử","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1593","text":"Cùng Hồng Sam Tử bước ra đối mặt tiên nhân nhưng bị lốc vàng huyết mạch trấn áp phải lui lại.","anchor":"Hồng Sam Tử, Nam Vân Tử sửng sốt một chút, lập tức thần sắc đại biến"}]},"nguon":["@c1593"]},{"id":"thanh-long-thanh-hoang","name":"Thanh Long Thánh Hoàng","aliases":["Thanh Long","Thanh Long chiến tướng"],"tabs":{"kinhLich":[{"mucCt":"vua","text":"Xuất hiện bên ngoài tiên giới dưới hình dạng lão già, hừ lạnh nhìn đám tiên nhân xông vào. Ôm quyền xin lỗi thân ảnh Vương Lâm, hứa quản giáo nghiêm, giữ giao dịch cũ, cam kết viễn cổ tiên vực sẽ không giết tu sĩ giới nội.","anchor":"Lão phu quản giáo không nghiêm, đã tới chậm một bước, mong đạo hữu lượng thứ","bridge":true,"khoang":"@c1593"},{"importance":"bridge","mucCt":"vua","chuong":"@c1594","tieuDe":"Chứng kiến uy lực cung Lý Quảng, cảnh giác Vương Lâm","text":"Đứng trong tinh không giới nội chứng kiến viễn cổ tiên vực giới ngoại chấn động bởi cung Lý Quảng, thở dài nói không nên trêu chọc người này.","anchor":"chúng ta không nên trêu chọc là tốt nhất"},{"importance":"bridge","mucCt":"gon","chuong":"@c1606","tieuDe":"","text":"Trong ký ức đại chiến, đang chém giết với thiếu niên đầu trọc áo vải xanh phía sau Liên Đạo Phi tại sơn môn Thất Thải Tiên Tôn.","anchor":"Người này Vương Lâm cũng không xa lạ, đó là Thanh Long chiến tướng trong tứ đại chiến tướng!"}],"nhanMach":[],"tuViMoc":[]},"nguon":["@c1593","@c1594","@c1606"],"trangThai":"song","gioiTinh":"nam"},{"id":"tien-phi-thu-bay","name":"Tiên phi thứ bảy","aliases":["Thất phi","tiên phi thứ bảy"],"gioiTinh":"nu","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Đạo lữ cũ của Thất Thải Tiên Tôn, bị hắn vứt bỏ khi lâm nguy. Chỉ huy đệ tử Thất Đạo Tông phong ấn trong viễn cổ tiên vực giới ngoại, đệ tử này là lá bài sát thủ cuối cùng của nàng.","vaiTro":"Tiên phi chỉ huy đệ tử Thất Đạo Tông trong viễn cổ tiên vực giới ngoại","tinhCach":"Kiên quyết; mưu tính lâu dài","tabs":{"diem":[{"text":"Đạo lữ cũ bị Thất Thải Tiên Tôn vứt bỏ khi lâm nguy, nắm giữ lá bài sát thủ cuối cùng là đám đệ tử Thất Đạo Tông phong ấn trong viễn cổ tiên vực giới ngoại.","chuong":"@c1593"}],"kinhLich":[{"importance":"normal","mucCt":"gon","chuong":"@c1593","tieuDe":"Sắc mặt kịch biến, lao về phía Vương Lâm","text":"Khi rõ mục đích Vương Lâm muốn hủy viễn cổ tiên vực giới ngoại, sắc mặt biến hóa kịch liệt, lao thẳng về phía hắn.","anchor":"sau khi rõ mục đích của Vương Lâm, tiên phi thứ bảy sắc mặt biến hóa kịch liệt"},{"chuong":"@c1597","importance":"normal","mucCt":"vua","tieuDe":"Nhận ra đại tỷ Phàn San Lộ còn sống","text":"May mắn sống sót nhờ pháp bảo sau khi chịu lực cung Lý Quảng. Nhận ra ấn quyết đại tỷ, thất thanh xác nhận đệ nhất phi còn sống.","anchor":"Đại tỷ! Người không chết!"}],"tuViMoc":[],"nhanMach":[{"ten":"Thất Thải Tiên Tôn","tag":"the-thiep","quanHe":"Đạo lữ cũ, bị Thất Thải Tiên Tôn vứt bỏ khi lâm nguy"},{"ten":"Phàn San Lộ","tag":"dong-minh","quanHe":"Đại tỷ (đệ nhất phi)","ghiChu":"Nhận ra ấn quyết đại tỷ từ hắc động, xác nhận nàng còn sống"},{"ten":"Phàn San Lộ","tag":"ho-hang","quanHe":"Đại tỷ đồng môn","ghiChu":"Đệ nhất phi Thất Đạo Tông, tưởng đã chết nay xác nhận còn sống"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1593","@c1597"]},{"id":"huyen-vu","name":"Huyền Vũ","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"vua","chuong":"@c1594","tieuDe":"Đoán Vương Lâm có lực bắn ba mũi tên","text":"Phân tích rằng Vương Lâm tâm trí cẩn thận không để lộ nhược điểm, đoán hắn nhất định có lực lượng bắn ba mũi tên chứ không chỉ hai, bốn chiến tướng giới nội đều gật đầu đồng ý.","anchor":"Ta đoán là hắn nhất định có lực lượng bắn ba mũi tên"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c1594"]},{"id":"phan-san-lo","name":"Phàn San Lộ","cn":"樊山露","aliases":["đệ nhất phi"],"gioiTinh":"nữ","theLuc":[{"ten":"Thất Đạo Tông","trangThai":"da-roi"},{"ten":"Đại Hồn Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Đệ nhất phi trong thất phi của Thất Đạo Tông, thân phận thật là muội muội của Phàn San Mộng (đạo lữ Thất Thải Thiên Tôn), đệ tử hạch tâm Đại Hồn Môn thuộc Cửu Vũ Thập Tam Môn. Bị Thất Thải Thiên Tôn gây thương tích mãi không khôi phục, ẩn náu trong khe sâu Yêu Tông cũ.","vaiTro":"Đệ nhất phi Thất Đạo Tông, đồng minh hợp tác với Vương Lâm, đệ tử hạch tâm Đại Hồn Môn","tinhCach":"Cẩn trọng, không tin bất cứ ai từ Tiên Cương đại lục; kiên nhẫn chờ đợi cơ hội báo thù; trọng lời hứa, giữ ước hẹn với Vương Lâm","tabs":{"diem":[{"text":"Muội muội đạo lữ Thất Thải Thiên Tôn, bị hắn phản bội gây thương tích không thể khôi phục","chuong":"@c1597"},{"text":"Đệ tử hạch tâm Đại Hồn Môn thuộc Cửu Vũ Thập Tam Môn, có thể giúp Vương Lâm nhập môn phái tại Tiên Cương đại lục","chuong":"@c1597"},{"text":"Thi triển Thái Ngọc Thất Thủ Ấn chặn đòn đạo nhân bảy màu, cứu Vương Lâm thoát thân","chuong":"@c1597"},{"text":"Thi triển Thái Ngọc Thất Thủ Ấn đỡ đòn đạo nhân bảy màu cứu Vương Lâm","chuong":"@c1597"}],"kinhLich":[{"chuong":"@c1597","importance":"major","mucCt":"ky","tieuDe":"Đỡ đòn cứu Vương Lâm, tiết lộ thân phận và đề nghị hợp tác","text":"Từ hắc động vươn ngọc thủ đeo nhẫn xanh biếc ngón giữa đỡ chỉ phong bảy màu của đạo nhân bảy màu, thi triển Thái Ngọc Thất Thủ Ấn nhưng bị khí bảy màu xâm nhập rên đau. Cứu Vương Lâm thoát vào hắc động tới khe sâu Yêu Tông cũ. Tiết lộ tên thật Phàn San Lộ, từng là đệ nhất phi Thất Đạo Tông, muội muội Phàn San Mộng — đạo lữ Thất Thải Thiên Tôn. Kể quá khứ bị phản bội: Thất Thải Thiên Tôn dùng tỷ tỷ làm mồi đoạt bảo vật liên quan vầng mặt trời thứ chín, phong kín Thất Đạo Tông, gây thương tích cho nàng mãi không khôi phục. Đề nghị Vương Lâm giết Thất Thải Thiên Tôn đoạt sơn môn, hứa giúp nhập Đại Hồn Môn và cầu sư tôn giảm kiếp nạn nhập giới Tiên Cương đại lục. Khẳng định Phàn San Mộng chưa chết, đang ở Tiên Cương đại lục.","anchor":"muội muội của đạo lữ của Thất Thải Thiên Tôn – Phàn San Mộng, tên ta là Phàn San Lộ!"},{"chuong":"@c1598","importance":"normal","mucCt":"ky","tieuDe":"Bị gọi đệ nhất phi, cầu viện tỷ tỷ phá vây","text":"Dùng huyết tế sư thú dụ mãnh thú cản đường đạo nhân bảy màu. Bị đạo nhân gọi là đệ nhất phi của bổn tôn. Thi triển Đại Hồn đạo — Dẫn Hồn Minh, tế hiến hồn hóa trường đao huyết sắc chém chín hỏa điểu. Khi bị tinh thể bảy màu vây khốn, kích hoạt thủ ấn bảy màu và kêu gọi tỷ tỷ — một nữ tử giống hệt nàng trong băng sơn Tiên Cương đại lục truyền lực xuyên không gian phá vây. Kiệt sức, được Vương Lâm mang về động phủ thuyền tím. Trả lời mập mờ về danh tính đạo nhân bảy màu: đúng mà cũng không phải.","anchor":"Ta nhớ rõ ngươi. Ngươi là đệ nhất phi của bổn tôn"},{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Thân xác bị Phàn San Mộng chiếm, được gọi là muội muội","text":"Thân xác trên thuyền thực chất do Phàn San Mộng chiếm/chia sẻ, được Phàn San Mộng gọi là muội muội — người đã tuyển Vương Lâm hợp tác.","anchor":"Không hổ là người được muội muội ta tuyển làm người hợp tác"},{"chuong":"@c1603","importance":"major","mucCt":"ky","tieuDe":"Bị Vương Lâm vạch trần giả dạng Phàn San Mộng","text":"Khi Vương Lâm sắp chiếm thuyền, nàng mở phòng hộ cho đạo nhân bảy màu vào nhưng bị Vương Lâm phản chế, buộc phải dùng toàn lực trì hoãn đạo nhân bảy màu ở tầng hai. Sau hai canh giờ tầng hai sụp đổ, nàng phun máu tươi. Tiến vào tầng bốn tiếp tục dụ Vương Lâm trao đổi thệ huyết. Bị Vương Lâm vạch trần danh tính thực là Phàn San Lộ — từ đầu đã phun máu biến hóa thần sắc khí tức giả dạng Phàn San Mộng, toàn bộ tầng hai đến tầng bốn cùng đạo nhân bảy màu trên thuyền đều là huyễn giới do nàng bày ra. Cười khổ phủ nhận nhưng không thể ngăn Vương Lâm đánh sập tầng ba.","anchor":"Hắn từng bước một cướp thế chủ động mà ta vẫn nắm trong tay"},{"mucCt":"ky","text":"Trong ảo cảnh kinh hãi lui lại, triệu kiếm bảy màu và hư ảnh đóa hoa bảy màu phòng thủ. Khi thức tỉnh mắt mở to mê man, bản thân cũng không biết đang ở trong ảo giác. Bị Vương Lâm chỉ ra đã rơi vào ảo thuật của tỷ tỷ Phàn San Mộng, sắc mặt tái nhợt phun máu tươi xác nhận. Tiết lộ Đại Hồn Môn nổi danh nhất bởi ảo thuật, tỷ tỷ đã đạt huyễn cảnh song trọng, nếu tam trọng thì không ai thoát.","anchor":"Đại Hồn Môn nổi danh nhất đúng là ảo thuật. Thuật này không phải ai cũng học được","bridge":true,"khoang":"@c1604"},{"chuong":"@c1605","importance":"normal","mucCt":"vua","tieuDe":"Trao bản đồ tế đàn và thệ huyết cho Vương Lâm","text":"Trao ngọc giản chứa bản đồ dẫn tới tế đàn và thuật thôn hồn người thứ ba cho Vương Lâm. Giải thích không gian vết rách hình thành từ trận chiến năm xưa, tiếp giáp kỳ dị với một giới. Tiết lộ điều kiện mở nội phủ Thất Thải Tiên Tôn: cần hồn thứ ba xuất hiện triệu hồi thiên đạo dẫn đường. Xin Vương Lâm mang mình về Tiên Cương đại lục, cắn lưỡi phun thệ huyết (máu đỏ chuyển vàng) trao cho hắn.","anchor":"Ta muốn về nhà"},{"mucCt":"gon","text":"Bị Thất Thải Tiên Tôn gọi tên chung với Phàn San Mộng khi chất vấn sự phản bội, cùng phe tấn công sơn môn.","anchor":"Phàn San Mộng. Phàn San Lộ, hai ngươi vì sao phản bội ta!","bridge":true,"khoang":"@c1606"}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đồng minh hợp tác","ghiChu":"Từng giúp Vương Lâm rời khỏi nơi ẩn náu, đạt thỏa thuận hợp tác qua ngọc giản"},{"ten":"Phàn San Mộng","tag":"ho-hang","quanHe":"Tỷ tỷ","ghiChu":"Đạo lữ Thất Thải Thiên Tôn, bị dùng làm mồi đoạt bảo vật, chưa chết, đang ở Tiên Cương đại lục"},{"ten":"Thất Thải Thiên Tôn","tag":"doi-thu","quanHe":"Kẻ thù","ghiChu":"Phản bội tỷ tỷ nàng, gây thương tích cho nàng không thể khôi phục"},{"ten":"Nữ tử trong băng sơn","tag":"ho-hang","quanHe":"Tỷ tỷ","ghiChu":"Tướng mạo giống hệt Phàn San Lộ, ngồi tu luyện trong núi băng Tiên Cương đại lục, truyền lực xuyên không gian cứu viện khi nàng bị vây khốn"},{"ten":"Thất phi","tag":"ho-hang","quanHe":"Muội muội đồng môn","ghiChu":"Phi thứ bảy Thất Đạo Tông, nhận ra đại tỷ còn sống"}],"tuiDo":{"phapBao":[{"ten":"Nhẫn xanh biếc","moTa":"Đeo ở ngón giữa ngọc thủ, chi tiết nhận dạng","nguon":"@c1597"}],"danDuoc":[],"congPhap":[{"ten":"Thái Ngọc Thất Thủ Ấn","moTa":"Ấn quyết hóa bảy bàn tay bảy màu công kích","nguon":"@c1597"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1597","@c1598","@c1599","@c1603","@c1604","@c1605","@c1606"]},{"id":"phan-san-mong","name":"Phàn San Mộng","cn":"樊山夢","aliases":["nữ tử trong băng sơn","nữ tử áo trắng","tỷ tỷ Phàn San Lộ"],"gioiTinh":"nữ","theLuc":[{"ten":"Đại Hồn Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Tỷ tỷ Phàn San Lộ, đạo lữ (bạn đời) của Thất Thải Thiên Tôn. Đệ tử hạch tâm Đại Hồn Môn. Bị Thất Thải Thiên Tôn dùng làm mồi đoạt bảo vật liên quan vầng mặt trời thứ chín, nhưng chưa chết, đang ở Tiên Cương đại lục.","vaiTro":"Đạo lữ Thất Thải Thiên Tôn, tỷ tỷ Phàn San Lộ, đệ tử hạch tâm Đại Hồn Môn","tinhCach":"Chưa rõ (chỉ được nhắc tới)","tabs":{"diem":[{"text":"Đạo lữ Thất Thải Thiên Tôn, bị hắn dùng làm mồi đoạt bảo vật liên quan vầng mặt trời thứ chín nhưng chưa chết","chuong":"@c1597"},{"text":"Tướng mạo giống hệt Phàn San Lộ, tu luyện trong núi băng Tiên Cương đại lục, có thể truyền lực xuyên không gian","chuong":"@c1598"},{"text":"Bị Thất Thải Tiên Tôn ám toán chiếm tu vi rồi giết, nhờ mệnh hồn sư tôn giữ mà sống lại bằng thuật luân hồi","chuong":"@c1599"},{"text":"Mượn pháp lực sư tôn, dụ Liên Đạo Phi và phối hợp muội muội Phàn San Lộ gây chia rẽ Thất Đạo Tông thành giới nội giới ngoại","chuong":"@c1599"},{"text":"Tiết lộ bên trong mảnh vỡ từ Thái Cổ Thần Cảnh chính là thiên đạo ngày nay","chuong":"@c1599"},{"text":"Đạt huyễn cảnh song trọng Đại Hồn chân ảo thuật, từ xa biến toàn bộ thực cảnh thành huyễn giới che mắt cả đồng minh lẫn kẻ thù","chuong":"@c1604"},{"text":"Là người thứ hai cả đời khiến Vương Lâm kiêng kỵ trong lòng","chuong":"@c1604"},{"text":"Vương Lâm suy luận nàng chưa từng chết, rất có thể dùng ảo thuật lừa gạt Thất Thải Tiên Tôn","chuong":"@c1604"},{"text":"Đạo lữ của Thất Thải Tiên Tôn nhưng phản bội, câu dẫn Liên Đạo Phi tấn công sơn môn để đoạt mảnh vỡ","chuong":"@c1606"}],"kinhLich":[{"chuong":"@c1597","importance":"normal","mucCt":"vua","tieuDe":"Được tiết lộ còn sống tại Tiên Cương đại lục","text":"Phàn San Lộ tiết lộ tỷ tỷ Phàn San Mộng chưa chết, đang ở Tiên Cương đại lục. Năm xưa bị Thất Thải Thiên Tôn dùng làm mồi đoạt bảo vật liên quan vầng mặt trời thứ chín.","anchor":"Tỷ tỷ của ta không chết!"},{"importance":"normal","mucCt":"ky","chuong":"@c1599","tieuDe":"Lộ diện tiết lộ thân phận và bí mật Thái Cổ Thần Cảnh","text":"Ẩn trong thân xác Phàn San Lộ, mi tâm có dòng xoáy bảy màu, sau dị biến chính thức lộ diện xưng danh Phàn San Mộng — tỷ tỷ của Phàn San Lộ, đạo lữ của Thất Thải Tiên Tôn. Gia cố tấm màn phòng hộ bằng ánh sáng bảy màu. Kể lại quá khứ: năm xưa cùng Thất Thải Tiên Tôn nhờ cơ duyên lấy được mảnh vỡ bảo vật từ Thái Cổ Thần Cảnh khi Đạo Nhất và Huyền La tranh đoạt. Bị Thất Thải Tiên Tôn ám toán trên đường về, chiếm hết tu vi rồi giết diệt khẩu. Nhờ mệnh hồn do sư tôn giữ được cứu sống bằng thuật luân hồi. Sau đó mượn pháp lực sư tôn, dụ Liên Đạo Phi tới, phối hợp muội muội Phàn San Lộ liên lạc các phi tử gây chia rẽ nội bộ Thất Đạo Tông thành giới nội giới ngoại. Tiết lộ đạo nhân bảy màu hiện tại không phải đầy đủ, và bên trong mảnh vỡ chính là thiên đạo ngày nay.","anchor":"Ta đích xác không phải là Phàn San Lộ, ta là tỷ tỷ nàng, Phàn San Mộng!"},{"importance":"normal","mucCt":"ky","chuong":"@c1600","tieuDe":"Tiết lộ bí mật ba hồn bảy phách — đề xuất hợp tác","text":"Kể tiếp toàn bộ diễn biến trận đại chiến giữa Liên Đạo Phi và Thất Thải Thiên Tôn: Liên Đạo Phi bị thiên đạo nuốt nhưng nhờ tiên nhân bất diệt thể không chết. Tiết lộ bí mật ba hồn bảy phách: kim thân Thất Thải Thiên Tôn tan nát hóa ba chủ hồn và thất phách, ai nuốt được hồn thứ ba sẽ có thể dung hợp tất cả thành Thất Thải Thiên Tôn mới. Đề xuất hai phương pháp giết Thất Thải Thiên Tôn: dụ hồn tới cửa động phủ để nguyên thần ra tay, hoặc dạy Vương Lâm thần thông thôn phệ hồn thứ ba rồi nuốt nốt tất cả. Gợi ý Vương Lâm trở thành Thất Thải Thiên Tôn mới, nàng làm đạo lữ song tu, muội muội làm phi tử. Hứa nhờ sư tôn đưa Vương Lâm tới Tiên Cương, tặng Thất Đạo Tông, giúp người thân Vương Lâm chuyển thế luân hồi. Đề nghị thệ huyết xác nhận hợp tác.","anchor":"Ta sẽ giúp ngươi thôn phệ đạo nhân bảy màu và hồn phách thứ hai"},{"mucCt":"ky","text":"Tiết lộ về tế đàn ở tầng cuối thuyền chứa cổ lực, đề xuất Vương Lâm dùng ba ngày phá phòng hộ tế đàn. Khinh thường năng lực cấm chế của Vương Lâm, thách đố nếu nghiên cứu ra cấm chế thuyền thì tặng luôn. Nội tâm lộ âm mưu: cần thệ huyết Vương Lâm để nhận trợ giúp sư tôn, dẫn động pháp thuật kỳ dị biến Vương Lâm thành con rối nhằm giết Thất Thải Tiên Tôn. Kinh ngạc khi Vương Lâm phá được tầng phòng hộ cấm chế boong tàu nhưng vẫn tự tin hắn không thể hoàn toàn nắm giữ trong ba ngày.","anchor":"Thệ huyết của Vương Lâm nàng muốn có. Dùng thệ huyết này nàng có thể nhận được sự trợ giúp của sư tôn, dẫn động một pháp thuật kỳ dị","bridge":true,"khoang":"@c1601"},{"mucCt":"vua","text":"Ban đầu cười lạnh khi thấy Vương Lâm bất động ba canh giờ, cho rằng hắn gặp chướng ngại và khuyên bỏ cuộc đi tế đàn nhưng bị phớt lờ. Kinh hoàng khi Vương Lâm phá cấm liên hoàn, bị đoạt quyền điều khiển thuyền ở cả tầng một và tầng hai, lúc này chỉ còn nhiều hơn Vương Lâm một chút. Lộ ra bản thể không thể tiến vào nơi này, chỉ phát huy chưa tới ba phần sức mạnh của thuyền.","anchor":"Ta không tin là một tu sĩ thấp hèn trong động phủ như hắn lại có thể hoàn toàn điều khiển chiếc thuyền này","bridge":true,"khoang":"@c1602"},{"chuong":"@c1604","importance":"normal","mucCt":"ky","tieuDe":"Thi triển Đại Hồn chân ảo thuật từ xa, bị Vương Lâm phá giải","text":"Từ xa ngồi trong hàn băng trên dãy núi đóng băng ở Tiên Cương đại lục, thi triển Đại Hồn chân ảo thuật biến toàn bộ cảnh tượng trên thuyền thành huyễn giới ngay từ lúc Vương Lâm xuất hiện. Huyễn hóa cả đạo nhân bảy màu tấn công, che mắt cả Phàn San Lộ lẫn Vương Lâm, thi triển huyễn trong huyễn suýt ép Vương Lâm giao thệ huyết. Bị Vương Lâm phá ảo thuật, phun máu tươi kinh hãi. Vương Lâm suy luận nàng chưa từng bị Thất Thải Tiên Tôn giết chết, rất có thể dùng ảo thuật lừa gạt hắn, thậm chí mối đạo lữ năm đó cũng chưa chắc thật.","anchor":"Hắn không ngờ lại phá được Đại Hồn chân ảo thuật của ta!"},{"importance":"normal","mucCt":"vua","chuong":"@c1606","tieuDe":"Phản bội Thất Thải Tiên Tôn","text":"Từng đánh lén Thất Thải Tiên Tôn trên đường nhưng được tha không giết. Sau đó câu dẫn Liên Đạo Phi dẫn ngoại nhân tới tấn công sơn môn Tiên Tôn để đoạt mảnh vỡ. Đạo nhân bảy màu trong huyễn cảnh thì thào nhớ lại tên nàng.","anchor":"San Mộng.ta nhớ rồi. Tên nàng là Phàn San Mộng"}],"tuViMoc":[],"nhanMach":[{"ten":"Phàn San Lộ","tag":"ho-hang","quanHe":"Muội muội","ghiChu":"Đệ nhất phi Thất Đạo Tông, đệ tử hạch tâm Đại Hồn Môn"},{"ten":"Thất Thải Thiên Tôn","tag":"the-thiep","quanHe":"Đạo lữ (bạn đời)","ghiChu":"Phản bội nàng, dùng làm mồi đoạt bảo vật"},{"ten":"Thất Thải Tiên Tôn","tag":"doi-thu","quanHe":"Đạo lữ cũ, kẻ phản bội","ghiChu":"Từng là đạo lữ, bị hắn ám toán chiếm tu vi rồi giết"},{"ten":"Liên Đạo Phi","tag":"khac","quanHe":"Người bị dụ lợi dụng","ghiChu":"Vốn mê sắc đẹp nàng, bị nàng dụ tới Thất Đạo Tông phá cuộc"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người hợp tác do muội muội tuyển","ghiChu":"Kể quá khứ cho Vương Lâm nghe trên chiến thuyền"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Phá được Đại Hồn chân ảo thuật của nàng, chiếm cánh buồm mặt quỷ"},{"ten":"Thất Thải Tiên Tôn","tag":"khac","quanHe":"Cựu đạo lữ","ghiChu":"Vương Lâm suy luận nàng dùng ảo thuật giả chết lừa gạt hắn"},{"ten":"Thất Thải Tiên Tôn","tag":"the-thiep","quanHe":"Đạo lữ (bạn đường)","ghiChu":"Phản bội, dẫn ngoại nhân tấn công sơn môn"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1597","@c1598","@c1599","@c1600","@c1601","@c1602","@c1604","@c1606"]},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","trangThai":"song","tabs":{"kinhLich":[],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1598"]},{"id":"luu-kim-buu","name":"Lưu Kim Bưu","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Nhân vật được nhắc đến cùng Hứa Lập Quốc, năm xưa hai người lừa giọt huyết mạch tiên nhân từ người điên.","vaiTro":"Nhân vật phụ, đồng mưu cùng Hứa Lập Quốc lừa giọt huyết mạch","tinhCach":"Mưu mô","tabs":{"diem":[{"text":"Cùng Hứa Lập Quốc lừa giọt huyết mạch tiên nhân từ người điên, giọt máu này cuối cùng rơi vào tay Vương Lâm","chuong":"@c1598"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Hứa Lập Quốc","tag":"dong-minh","quanHe":"Đồng mưu","ghiChu":"Cùng lừa giọt huyết mạch tiên nhân từ người điên"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1598"]},{"id":"dao-nhat-dai-thien-ton","name":"Đạo Nhất đại thiên tôn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Đại thiên tôn","trangThai":"khong-ro","blurb":"Đại thiên tôn từng tranh đoạt bảo vật bay ra từ Thái Cổ Thần Cảnh cùng Huyền La đại thiên tôn tại phụ cận Thất Đạo Tông khi mặt trời thứ chín xuất hiện.","vaiTro":"Đại thiên tôn được nhắc trong quá khứ tranh đoạt bảo vật Thái Cổ Thần Cảnh","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Tranh đoạt bảo vật từ Thái Cổ Thần Cảnh cùng Huyền La đại thiên tôn","chuong":"@c1599"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Nhắc tới tranh bảo vật Thái Cổ Thần Cảnh","text":"Được Phàn San Mộng nhắc: khi mặt trời thứ chín xuất hiện, cùng Huyền La đại thiên tôn tranh đoạt bảo vật bay ra từ Thái Cổ Thần Cảnh tại phụ cận Thất Đạo Tông.","anchor":"Đạo Nhất đại thiên tôn và Cổ quốc Huyền La đại thiên tôn xuất hiện tại phụ cận của Thất Đạo Tông ta"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1599"]},{"id":"huyen-la-dai-thien-ton","name":"Huyền La đại thiên tôn","cn":"","aliases":["Cổ quốc Huyền La đại thiên tôn"],"gioiTinh":"khong-ro","theLuc":[{"ten":"Cổ quốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Đại thiên tôn","trangThai":"khong-ro","blurb":"Đại thiên tôn thuộc Cổ quốc, từng cùng Đạo Nhất đại thiên tôn tranh đoạt bảo vật từ Thái Cổ Thần Cảnh tại phụ cận Thất Đạo Tông.","vaiTro":"Đại thiên tôn Cổ quốc được nhắc trong sự kiện tranh bảo vật","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Cùng Đạo Nhất tranh đoạt bảo vật Thái Cổ Thần Cảnh","chuong":"@c1599"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Nhắc tới tranh bảo vật Thái Cổ Thần Cảnh","text":"Được Phàn San Mộng nhắc: cùng Đạo Nhất đại thiên tôn tranh đoạt bảo vật từ Thái Cổ Thần Cảnh khi mặt trời thứ chín xuất hiện.","anchor":"Đạo Nhất đại thiên tôn và Cổ quốc Huyền La đại thiên tôn xuất hiện tại phụ cận của Thất Đạo Tông ta"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1599"]},{"id":"khong-huyen","name":"Không Huyền","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Toàn năng","trangThai":"khong-ro","blurb":"Bậc toàn năng mà Vương Lâm cần cung Lý Quảng để đối đầu.","vaiTro":"Bậc toàn năng, đối thủ tiềm tàng của Vương Lâm","tinhCach":"Không rõ","tabs":{"diem":[{"text":"Bậc toàn năng mà Vương Lâm xác định cần cung Lý Quảng để đấu","chuong":"@c1599"}],"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Được Vương Lâm nhắc tới","text":"Vương Lâm nhắc cần giữ cung Lý Quảng để đấu với bậc toàn năng Không Huyền.","anchor":"hắn muốn đấu với bậc toàn năng Không Huyền đều phải dựa vào nó"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1599"]},{"id":"ly-quang","name":"Lý Quảng","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Nhắc tới chém giết Đạo Cổ Diệp Mịch","text":"Được Phàn San Mộng nhắc: Thất Thải Tiên Tôn không rõ bằng cách nào khiến Lý Quảng trợ giúp chém giết Đạo Cổ Diệp Mịch.","anchor":"Ta không biết hắn làm sao khiến Lý Quảng trợ giúp mà chém giết Đạo Cổ Diệp Mịch"}]},"nguon":["@c1599"]},{"id":"dao-co-diep-mich","name":"Đạo Cổ Diệp Mịch","tabs":{"kinhLich":[{"importance":"bridge","mucCt":"gon","chuong":"@c1599","tieuDe":"Nhắc tới bị dụ đến và bị Lý Quảng chém giết","text":"Được Phàn San Mộng nhắc: bị Thất Thải Tiên Tôn dụ tới phong kín tông sơn Thất Đạo Tông, rồi bị Lý Quảng chém giết.","anchor":"Ta không biết hắn làm sao khiến Lý Quảng trợ giúp mà chém giết Đạo Cổ Diệp Mịch"}]},"nguon":["@c1599"]},{"id":"that-thai-thien-ton","name":"Thất Thải Thiên Tôn","aliases":["đạo nhân bảy màu","Quái nhân tóc bạc","Thất Thải Tiên Tôn"],"tabs":{"kinhLich":[{"importance":"normal","mucCt":"ky","chuong":"@c1600","tieuDe":"Kim thân tan nát — hóa ba hồn bảy phách","text":"Được tiết lộ: kim thân tan nát sau đại chiến, hóa thành ba chủ hồn. Hồn thứ nhất chứa đạo thuật thần thông chính là đạo nhân bảy màu, chiếm cứ giới ngoại. Hồn thứ hai chứa ý cảnh và bổn nguyên lực, bỏ chạy sau đại chiến. Hồn thứ ba nắm toàn bộ trí nhớ và bí mật triệu hoán thiên đạo, đã trải vô số luân hồi có thể quên thân phận. Ngoài ra có thất phách cũng luân hồi thay đổi thân phận. Ai nuốt được hồn thứ ba mới có thể dung hợp tất cả trở thành Thất Thải Thiên Tôn hoàn chỉnh.","anchor":"Kim thân của Thất Thải Thiên Tôn tan nát, hoá thành một chủ hồn"},{"chuong":"@c1601","importance":"bridge","mucCt":"gon","text":"Bên ngoài thuyền liên tục vung tay phóng cuồng phong tấn công tầng sáng phòng hộ, phá vỡ hơn một nửa.","anchor":"đạo nhân bảy màu đang không ngừng vung hai tay về phía trước, mỗi lần vung tay áo đều có cuồng phong gào thét"},{"importance":"bridge","mucCt":"gon","chuong":"@c1602","tieuDe":"Tiếp tục phá tầng sáng thuyền cổ","text":"Tiếp tục tấn công tầng sáng bảo hộ bên ngoài thuyền cổ, sau một ngày đã phá hơn một nửa.","anchor":"đạo nhân bảy màu ở bên ngoài con thuyền ánh mắt cũng sững lại, cẩn thận nhìn tới"},{"chuong":"@c1604","importance":"normal","mucCt":"vua","tieuDe":"Tự nguyện đắm chìm trong ảo giác","text":"Ở một hướng khác trong không gian kỳ dị của chiếc thuyền, khoanh chân ngồi trên thi thể mãnh thú, thần sắc lúc thống khổ lúc hưng phấn, tự nguyện đắm chìm trong ảo giác dù với tu vi của hắn thoát ra không khó. Lý do cam tâm ở lại chỉ mình hắn biết.","anchor":"hắn tự nguyện chìm vào trong đó. nếu không với tu vi của hắn thì dù không bằng Phàn San Mộng nhưng muốn ra khỏi ảo giác này cũng không khó"},{"importance":"normal","mucCt":"ky","chuong":"@c1606","tieuDe":"Ký ức đại chiến — triệu Thiên Đạo đồng quy vu tận","text":"Trong thực tại, tỏa uy áp kinh khiếp hơn thiên uy, xung quanh đầy thi thể mãnh thú, chìm trong ảo giác. Trong huyễn cảnh, ngồi khoanh chân trên đỉnh núi, mắt mở to nhìn trời thẫn thờ, thì thào nhắc tên Phàn San Mộng, bên ngoài thân có chín quang cầu chứa hỏa điểu (pháp bảo chín mặt trời). Trong ký ức đại chiến: bị liên minh Liên Đạo Phi, Phàn San Mộng, Phàn San Lộ tấn công tại sơn môn, bị đánh phun máu. Phẫn nộ chất vấn sự phản bội, nhắc San Mộng từng đánh lén nhưng được tha mạng nay lại dẫn ngoại nhân tới. Cuối cùng vung tay triệu hồi dòng xoáy trên trời lộ ra đôi mắt vô tình — Thiên Đạo — đồng quy vu tận. Thân thể tan nát vỡ thành ba phần: hồn thứ nhất là đạo nhân bảy màu, hồn thứ hai là ý cảnh, hồn thứ ba chứa toàn bộ trí nhớ hóa cầu vồng bay đi. Phần đạo nhân bảy màu lao tới cố lấy lại phần trí nhớ — đây chính là nguyên nhân hắn tự giam trong ảo giác.","anchor":"Phàn San Mộng. Phàn San Lộ, hai ngươi vì sao phản bội ta!"}],"tuViMoc":[],"nhanMach":[{"ten":"Phàn San Mộng","tag":"the-thiep","quanHe":"Đạo lữ (bạn đường/người tình)","ghiChu":"Phản bội, câu dẫn Liên Đạo Phi tấn công sơn môn"},{"ten":"Phàn San Lộ","tag":"doi-thu","quanHe":"Kẻ phản bội","ghiChu":"Cùng Phàn San Mộng phản bội Tiên Tôn"},{"ten":"Liên Đạo Phi","tag":"doi-thu","quanHe":"Kẻ tấn công sơn môn","ghiChu":"Bị Phàn San Mộng câu dẫn tới, muốn mảnh vỡ"}],"tuiDo":{}},"nguon":["@c1600","@c1601","@c1602","@c1604","@c1606"],"trangThai":"khong-ro","cn":"七彩仙尊","gioiTinh":"nam"},{"id":"thieu-nien-dau-troc","name":"Thiếu niên đầu trọc áo vải xanh","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Thiếu niên bí ẩn phía sau Liên Đạo Phi trong đại chiến tại sơn môn Thất Thải Tiên Tôn, thân hình gầy gò, mắt hung quang, đang chém giết với Thanh Long chiến tướng.","vaiTro":"Chiến binh theo Liên Đạo Phi trong đại chiến tại sơn môn Tiên Tôn","tinhCach":"Hung hãn","tabs":{"diem":[{"text":"Gầy gò, mặc y phục kỳ quái bằng vải xanh, mắt hung quang, chiến đấu với Thanh Long chiến tướng","chuong":"@c1606"}],"kinhLich":[{"mucCt":"vua","text":"Xuất hiện phía sau Liên Đạo Phi trong đại chiến tại sơn môn Thất Thải Tiên Tôn, thân hình gầy gò, mặc y phục kỳ quái bằng vải xanh, mắt hung quang, đang chém giết với Thanh Long chiến tướng.","anchor":"Người này Vương Lâm cũng không xa lạ, đó là Thanh Long chiến tướng trong tứ đại chiến tướng!","bridge":true,"khoang":"@c1606"}],"tuViMoc":[],"nhanMach":[{"ten":"Liên Đạo Phi","tag":"dong-minh","quanHe":"Chủ nhân / người dẫn dắt","ghiChu":"Theo sau Liên Đạo Phi trong đại chiến"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1606"]},{"id":"that-thai-tien-ton","name":"Thất Thải Tiên Tôn","aliases":["Đạo nhân bảy màu","đạo nhân bảy màu","Quái nhân tóc bạc"],"trangThai":"song","tabs":{"kinhLich":[{"chuong":"@c1586","importance":"normal","mucCt":"gon","tieuDe":"Từ bỏ đạo lữ phong tỏa Thất Đạo Tông","text":"Từ bỏ đạo lữ, phong tỏa Thất Đạo Tông để đoạt bảo vật cực kỳ quý trọng bên trong.","anchor":"Thất Thải Tiên Tôn từ bỏ đạo lữ, phong tỏa Thất Đạo Tông, muốn đạt được bảo vật cực kỳ quý trọng"},{"importance":"normal","mucCt":"ky","chuong":"@c1607","tieuDe":"Lợi dụng ảo giác truy tìm hồn thứ ba","text":"Dùng tu vi cường hãn sửa lại ảo giác của Phàn San Mộng, biến thành cảnh quay ngược thời gian về lúc thân thể bị phân ba hồn bảy phách, theo dõi hồn thứ ba bay vào giới nội rồi xuyên Vân Hải tinh vực hướng Triệu Hà. Đây là cơ hội đầu tiên trong vô số ngàn năm để tìm nơi luân hồi của hồn thứ ba — khát vọng cả đời. Kích động cực độ, phóng đại tinh đồ theo dõi. Thân thể thật ngồi khoanh chân trên đỉnh núi trong huyễn cảnh tầng một, được chín vầng mặt trời và chín hỏa điểu bảo vệ bằng quang nhiệt.","anchor":"Vô số ngàn năm qua, đây là cơ hội đầu tiên của hắn!"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1607","@c1586"]},{"id":"ham-ham","name":"Hàm Hàm","cn":"","aliases":[],"gioiTinh":"nữ","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Cô bé tầm tám tuổi mặc váy tím sống trong không gian kỳ dị dạng đào viên tiếp giáp tế đàn trong khe Vân Hải tinh vực. Cùng Oa Oa giam giữ Tham Lang suốt trăm năm bắt kể chuyện cổ.","vaiTro":"Cô bé bí ẩn trong đào viên, giam giữ Tham Lang","tinhCach":"Ngang tàng, không sợ kẻ mạnh; thích nghe chuyện cổ","tabs":{"diem":[{"text":"Cùng Oa Oa khuất phục và giam giữ Tham Lang suốt trăm năm bắt kể chuyện cổ, dù Tham Lang là tu sĩ cường đại","chuong":"@c1608"}],"kinhLich":[{"mucCt":"vua","text":"Nắm chân Tham Lang lôi lại khi hắn cố thoát ra qua khe nứt. Cùng Oa Oa giữ Tham Lang suốt trăm năm bắt kể chuyện cổ.","anchor":"Hắn lúc vừa tới nơi này không phải còn uy h**p chúng ta sao","bridge":true,"khoang":"@c1608"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Đồ Nam","tag":"khac","quanHe":"Người bị giam giữ, bắt kể chuyện cổ","ghiChu":"@c1608"},{"ten":"Oa Oa (đào viên)","tag":"ban-be","quanHe":"Bạn đồng hành trong đào viên","ghiChu":"@c1608"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1608"]},{"id":"oa-oa-dao-vien","name":"Oa Oa (đào viên)","cn":"","aliases":[],"gioiTinh":"nữ","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Cô bé tầm tám tuổi mặc váy xanh sống trong không gian kỳ dị dạng đào viên tiếp giáp tế đàn trong khe Vân Hải tinh vực. Cùng Hàm Hàm giam giữ Tham Lang suốt trăm năm bắt kể chuyện cổ.","vaiTro":"Cô bé bí ẩn trong đào viên, giam giữ Tham Lang","tinhCach":"Có vẻ nhân từ hơn nhưng vẫn giữ người; thích nghe chuyện cổ","tabs":{"diem":[{"text":"Tỏ vẻ không nỡ nhưng đề nghị Tham Lang kể chuyện cổ một ngàn năm mới được thả, cho thấy năng lực bí ẩn vượt xa vẻ ngoài trẻ nhỏ","chuong":"@c1608"}],"kinhLich":[{"mucCt":"vua","text":"Cùng Hàm Hàm giữ Tham Lang suốt trăm năm. Tỏ vẻ không nỡ nhưng rồi đề nghị Tham Lang kể chuyện cổ một ngàn năm mới được thả.","anchor":"Ngươi kể chuyện cổ cho chúng ta một ngàn năm ta sẽ thả cho ngươi rời đi","bridge":true,"khoang":"@c1608"}],"tuViMoc":[],"nhanMach":[{"ten":"Tư Đồ Nam","tag":"khac","quanHe":"Người bị giam giữ, bắt kể chuyện cổ","ghiChu":"@c1608"},{"ten":"Hàm Hàm","tag":"ban-be","quanHe":"Bạn đồng hành trong đào viên","ghiChu":"@c1608"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1608"]},{"id":"ma-su-huynh-quy-nhat","name":"Mã sư huynh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Quy Nhất tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Thành viên Quy Nhất tông, năm xưa dùng chí bảo của tông phái mở thông đạo tới động phủ Thất Đạo Tông rồi dẫn người đi vào, dặn lại không được mở Đông Đan chung.","vaiTro":"Tu sĩ Quy Nhất tông, người mở thông đạo tới động phủ Thất Đạo Tông","tinhCach":[{"text":"Kiên nghị, nghiên cứu lâu dài để đạt mục đích"}],"tabs":{"diem":[{"text":"Dùng chí bảo Quy Nhất tông mở thông đạo tới động phủ Thất Đạo Tông, dặn chuông không được mở, phải tự mình trở về","chuong":"@c1586"}],"kinhLich":[],"tuViMoc":[],"nhanMach":[{"ten":"Chưởng môn phân tông Quy Nhất","tag":"su-mon","quanHe":"Sư đệ trong Quy Nhất tông","ghiChu":"Chưởng môn nhắc đến lời dặn của Mã sư huynh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1586"]},{"id":"nu-tu-bang-son","name":"Nữ tử trong băng sơn","cn":"","aliases":["Tỷ tỷ Phàn San Lộ"],"gioiTinh":"nữ","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Nữ tử tướng mạo giống hệt Phàn San Lộ, tu luyện trong núi băng vùng đóng băng Tiên Cương đại lục, có thể truyền lực xuyên không gian trợ giúp Phàn San Lộ.","vaiTro":"Tỷ tỷ của Phàn San Lộ, xuất hiện qua liên kết xuyên không gian khi Phàn San Lộ kêu cứu.","tinhCach":[{"text":"Chưa rõ, chỉ biết lập tức đáp ứng khi Phàn San Lộ cầu viện"}],"tabs":{"diem":[{"text":"Tướng mạo giống hệt Phàn San Lộ, tu luyện trong băng sơn Tiên Cương đại lục, truyền lực xuyên không gian phá vây cho muội muội.","chuong":"@c1598"}],"kinhLich":[{"chuong":"@c1598","importance":"normal","mucCt":"vua","tieuDe":"Truyền lực xuyên không gian cứu Phàn San Lộ","text":"Khi Phàn San Lộ bị đạo nhân bảy màu vây khốn bằng tinh thể và kêu cứu, nữ tử mở mắt, điểm chỉ lên mi tâm, phóng ánh sáng bảy màu truyền lực xuyên không gian tới Phàn San Lộ, khiến ấn quyết bành trướng mấy ngàn trượng phá vây.","anchor":"Trong lòng đất đóng băng này có một núi băng. Bên trong đó có một nữ tử ngồi khoanh chân"}],"tuViMoc":[],"nhanMach":[{"ten":"Phàn San Lộ","tag":"ho-hang","quanHe":"Muội muội, tướng mạo giống hệt, truyền lực xuyên không gian cứu viện khi bị vây khốn","ghiChu":"@c1598"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c1598"]}]};
